import React from 'react';
import { Card, Stack, Row, Text, Divider, Heading } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

/**
 * Weather icon mapping from condition text to emoji
 */
function getWeatherEmoji(condition: string): string {
  const conditionLower = condition.toLowerCase();

  if (conditionLower.includes('sunny') || conditionLower.includes('sunny')) return '☀️';
  if (conditionLower.includes('partly cloudy')) return '⛅';
  if (conditionLower.includes('cloudy') || conditionLower.includes('cloud')) return '☁️';
  if (conditionLower.includes('overcast')) return '🌫️';
  if (conditionLower.includes('rainy') || conditionLower.includes('rain')) return '🌧️';
  if (conditionLower.includes('storm') || conditionLower.includes('thunder')) return '⛈️';
  if (conditionLower.includes('snow') || conditionLower.includes('sleet')) return '❄️';

  return '🌡️'; // Default
}

export default function WeatherCard({
  city = 'Unknown',
  temperature = 0,
  condition = 'Clear',
  humidity = 0,
  windSpeed = 0,
  unit = '°C',
  forecast = [],
}: Props) {
  const weatherEmoji = getWeatherEmoji(condition);

  return (
    <Card padding={24} shadow="md" border={true}>
      <Stack direction="vertical" gap={16}>
        {/* Section 1: Header with City and Current Conditions */}
        <Stack direction="vertical" gap={8}>
          {/* City Name */}
          <Heading
            level={3}
            style={{
              color: 'var(--ggui-color-onSurface, #18181b)',
              fontWeight: 'var(--ggui-font-weight-semibold, 600)',
            }}
          >
            {city}
          </Heading>

          {/* Temperature and Condition */}
          <Row gap={16} align="center" justify="start">
            {/* Large Temperature Display */}
            <Heading
              level={1}
              style={{
                color: 'var(--ggui-color-primary-600, #0284c7)',
                lineHeight: '1',
              }}
            >
              {temperature}
              <span style={{ fontSize: '0.6em' }}>{unit}</span>
            </Heading>

            {/* Weather Icon and Condition */}
            <Stack direction="vertical" gap={4} align="start">
              <div style={{ fontSize: '3rem', lineHeight: '1' }}>
                {weatherEmoji}
              </div>
              <Text
                variant="body"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                {condition}
              </Text>
            </Stack>
          </Row>
        </Stack>

        {/* Section 2: Current Metrics (Humidity & Wind) */}
        <Divider orientation="horizontal" margin={16} />

        <Row gap={24} justify="between" align="center">
          {/* Humidity */}
          <Stack direction="vertical" gap={4} align="start">
            <Text
              variant="label"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
              weight="normal"
            >
              Humidity
            </Text>
            <Heading
              level={3}
              style={{
                color: 'var(--ggui-color-primary-500, #0ea5e9)',
                fontWeight: 'var(--ggui-font-weight-bold, 700)',
              }}
            >
              {humidity}%
            </Heading>
          </Stack>

          {/* Wind Speed */}
          <Stack direction="vertical" gap={4} align="start">
            <Text
              variant="label"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
              weight="normal"
            >
              Wind Speed
            </Text>
            <Heading
              level={3}
              style={{
                color: 'var(--ggui-color-primary-500, #0ea5e9)',
                fontWeight: 'var(--ggui-font-weight-bold, 700)',
              }}
            >
              {windSpeed} km/h
            </Heading>
          </Stack>
        </Row>

        {/* Section 3: 5-Day Forecast Strip */}
        {forecast && forecast.length > 0 && (
          <>
            <Divider orientation="horizontal" margin={16} />

            <Stack direction="vertical" gap={12}>
              <Text
                variant="label"
                weight="semibold"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                5-Day Forecast
              </Text>

              <Row gap={12} justify="between" wrap={false}>
                {forecast.map((item, index) => {
                  const dayName = item.day || `Day ${index + 1}`;
                  const icon = item.icon || '☁️';
                  const high = item.high !== undefined ? item.high : 'N/A';
                  const low = item.low !== undefined ? item.low : 'N/A';

                  return (
                    <div
                      key={`${dayName}-${index}`}
                      style={{
                        flex: '1 1 auto',
                        minWidth: '70px',
                        padding: 'var(--ggui-spacing-2, 8px)',
                        backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
                        border: '1px solid var(--ggui-color-primary-200, #bae6fd)',
                        borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                      }}
                    >
                      <Stack direction="vertical" gap={4} align="center">
                        {/* Day Name */}
                        <Text
                          variant="label"
                          weight="medium"
                          color="var(--ggui-color-onSurface, #18181b)"
                          align="center"
                        >
                          {dayName}
                        </Text>

                        {/* Weather Icon */}
                        <div
                          style={{
                            fontSize: '1.5rem',
                            lineHeight: '1',
                          }}
                        >
                          {icon}
                        </div>

                        {/* High/Low Temps */}
                        <Row gap={4} justify="center" align="center">
                          <Text
                            variant="caption"
                            weight="bold"
                            color="var(--ggui-color-primary-700, #0369a1)"
                          >
                            {high}°
                          </Text>
                          <Text
                            variant="caption"
                            color="var(--ggui-color-onSurfaceVariant, #52525b)"
                          >
                            /
                          </Text>
                          <Text
                            variant="caption"
                            color="var(--ggui-color-onSurfaceVariant, #52525b)"
                          >
                            {low}°
                          </Text>
                        </Row>
                      </Stack>
                    </div>
                  );
                })}
              </Row>
            </Stack>
          </>
        )}
      </Stack>
    </Card>
  );
}

import React, { useState, useCallback } from 'react';
import { Container, Card, Stack, Row, Text, Button, Input, Select, Badge, Icon, Divider, Box } from '@ggui-ai/design/primitives';

interface Task {
  id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string; [key: string]: unknown;
}

interface Column {
  id?: string; name?: string;
}

interface Props {
  tasks?: Task[]; columns?: Column[]; onTaskUpdate?: (payload: { action: string; taskId?: string; data?: Record<string, unknown> }) => void;
}

export default function KanbanBoard({ tasks = [], columns = [{ id: 'todo', name: 'To Do' }, { id: 'in-progress', name: 'In Progress' }, { id: 'done', name: 'Done' }], onTaskUpdate }: Props) {
  const [localTasks, setLocalTasks] = useState<Task[]>(tasks);
  const [addingColumnId, setAddingColumnId] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  const getTasksForColumn = (columnId?: string) => localTasks.filter((task) => task.column === columnId);

  const handleAddTask = useCallback(async (columnId?: string) => {
    if (!newTaskTitle.trim()) return;
    setIsSubmitting(true);
    try {
      const newTask: Task = { id: `task-${Date.now()}`, title: newTaskTitle, priority: newTaskPriority, assignee: '', column: columnId, dueDate: '' };
      setLocalTasks((prev) => [...prev, newTask]);
      onTaskUpdate?.({ action: 'Task Created', taskId: newTask.id, data: newTask });
      setNewTaskTitle('');
      setNewTaskPriority('medium');
      setAddingColumnId(null);
    } finally {
      setIsSubmitting(false);
    }
  }, [newTaskTitle, newTaskPriority, onTaskUpdate]);

  const handleMoveTask = useCallback((taskId?: string, targetColumnId?: string) => {
    setLocalTasks((prev) => prev.map((task) => task.id === taskId ? { ...task, column: targetColumnId } : task));
    onTaskUpdate?.({ action: 'Task Moved', taskId, data: { column: targetColumnId } });
  }, [onTaskUpdate]);

  const handleEditTask = useCallback((taskId?: string, newTitle?: string) => {
    setLocalTasks((prev) => prev.map((task) => task.id === taskId ? { ...task, title: newTitle } : task));
    onTaskUpdate?.({ action: 'Task Edited', taskId, data: { title: newTitle } });
    setEditingTaskId(null);
    setEditingTitle('');
  }, [onTaskUpdate]);

  const getPriorityColor = (priority?: string) => {
    switch (priority) {
      case 'high': return 'error';
      case 'medium': return 'warning';
      case 'low': return 'success';
      default: return 'default';
    }
  };

  const totalTasks = localTasks.length;
  const completedTasks = localTasks.filter((t) => t.column === 'done').length;

  return (
    <Container maxWidth="full" padding={24}>
      <Stack direction="vertical" gap={24}>
        <Card shadow="sm" border padding={16}>
          <Row justify="between" align="center">
            <Stack direction="horizontal" gap={24}>
              <Stack direction="vertical" gap={4}>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Total Tasks</Text>
                <Text variant="bodyLarge" color="var(--ggui-color-onSurface, #18181b)" weight="bold">{totalTasks}</Text>
              </Stack>
              <Stack direction="vertical" gap={4}>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Completed</Text>
                <Text variant="bodyLarge" color="var(--ggui-color-success-500, #22c55e)" weight="bold">{completedTasks}</Text>
              </Stack>
            </Stack>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Progress: {totalTasks > 0 ? Math.round((completedTasks / totalTasks) * 100) : 0}%</Text>
          </Row>
        </Card>

        <Row gap={20} align="start" wrap>
          {columns.map((column) => {
            const columnTasks = getTasksForColumn(column.id);
            return (
              <Box key={column.id} style={{ flex: '1 1 300px', minWidth: '300px', backgroundColor: 'var(--ggui-color-surface, #fafafa)', borderRadius: 'var(--ggui-shape-radius-lg, 12px)', border: `1px solid var(--ggui-color-outline, #d4d4d8)`, padding: 'var(--ggui-spacing-4, 16px)', display: 'flex', flexDirection: 'column', gap: 'var(--ggui-spacing-2, 8px)' }}>
                <Row justify="between" align="center">
                  <Stack direction="horizontal" gap={8} align="center">
                    <Text variant="label" color="var(--ggui-color-onSurface, #18181b)" weight="semibold">{column.name}</Text>
                    <Badge variant="secondary" size="sm">{columnTasks.length}</Badge>
                  </Stack>
                </Row>

                <Divider orientation="horizontal" margin={8} />

                <Stack direction="vertical" gap={12} style={{ flex: 1 }}>
                  {columnTasks.map((task) => (
                    <Card key={task.id} padding={12} shadow="sm" border style={{ backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)', borderColor: 'var(--ggui-color-outlineVariant, #e4e4e7)', cursor: 'default', transition: 'all 200ms ease-out' }}>
                      <Stack direction="vertical" gap={10}>
                        {editingTaskId === task.id ? (
                          <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--ggui-spacing-1, 4px)' }}>
                            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Edit task</Text>
                            <Input label="Task" value={editingTitle} onChange={setEditingTitle} placeholder="Task title" />
                          </div>
                        ) : (
                          <div style={{ padding: `var(--ggui-spacing-1, 4px) 0`, cursor: 'pointer', transition: 'opacity 200ms' }} onDoubleClick={() => { setEditingTaskId(task.id); setEditingTitle(task.title || ''); }} role="button" tabIndex={0} onKeyDown={(e: any) => { if (e.key === 'Enter' || e.key === ' ') { setEditingTaskId(task.id); setEditingTitle(task.title || ''); } }} aria-label={`Edit task: ${task.title}`}>
                            <Text variant="body" color="var(--ggui-color-onSurface, #18181b)" weight="medium">{task.title || 'Untitled'}</Text>
                          </div>
                        )}

                        <Row justify="between" align="center" gap={8}>
                          <Badge variant={getPriorityColor(task.priority)} size="sm" pill>{task.priority || 'medium'}</Badge>
                          {task.assignee && (<div style={{ width: 'calc(var(--ggui-spacing-4, 16px) + 12px)', height: 'calc(var(--ggui-spacing-4, 16px) + 12px)', borderRadius: '50%', backgroundColor: 'var(--ggui-color-primary-500, #0ea5e9)', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--ggui-color-primary-50, #f0f9ff)', fontSize: 'var(--ggui-font-size-xs, 12px)', fontWeight: 'var(--ggui-font-weight-semibold, 600)' }} title={`Assigned to ${task.assignee}`}>{task.assignee}</div>)}
                        </Row>

                        {task.dueDate && (<Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Due: {new Date(task.dueDate).toLocaleDateString()}</Text>)}

                        <Row gap={6} justify="between">
                          <Button size="xs" variant="ghost" onClick={() => { setEditingTaskId(task.id); setEditingTitle(task.title || ''); }} leftIcon={<Icon name="settings" size={14} />}>Edit</Button>
                          <Select value={task.column || ''} onChange={(targetColumnId) => handleMoveTask(task.id, targetColumnId)} options={columns.filter((c) => c.id !== task.column).map((c) => ({ value: c.id || '', label: `Move to ${c.name}` }))} placeholder="Move..." />
                        </Row>
                      </Stack>
                    </Card>
                  ))}
                </Stack>

                {addingColumnId === column.id ? (
                  <Card padding={12} shadow="sm" border>
                    <Stack direction="vertical" gap={10}>
                      <Input label="Title" placeholder="Enter task title" value={newTaskTitle} onChange={setNewTaskTitle} required />
                      <Select label="Priority" value={newTaskPriority} onChange={(val) => setNewTaskPriority(val as 'low' | 'medium' | 'high')} options={[{ value: 'low', label: 'Low Priority' }, { value: 'medium', label: 'Medium Priority' }, { value: 'high', label: 'High Priority' }]} />
                      <Row gap={8}>
                        <Button size="sm" variant="primary" fullWidth onClick={() => handleAddTask(column.id)} disabled={!newTaskTitle.trim() || isSubmitting} loading={isSubmitting}>{isSubmitting ? 'Adding...' : 'Add'}</Button>
                        <Button size="sm" variant="outline" onClick={() => { setAddingColumnId(null); setNewTaskTitle(''); setNewTaskPriority('medium'); }}>Cancel</Button>
                      </Row>
                    </Stack>
                  </Card>
                ) : (
                  <Button size="sm" variant="outline" fullWidth leftIcon={<Icon name="plus" size={16} />} onClick={() => setAddingColumnId(column.id)}>Add Task</Button>
                )}
              </Box>
            );
          })}
        </Row>
      </Stack>
    </Container>
  );
}

import { useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Input,
  Divider,
} from '@ggui-ai/design/primitives';

interface Element {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  elements: Element[];
}

export default function PeriodicTable({ elements = [] }: Props) {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedElement, setSelectedElement] = useState<Element | null>(null);

  const getCategoryColor = (category?: string): string => {
    const colorMap: Record<string, string> = {
      'Alkali Metals': 'var(--ggui-color-error-500, #ef4444)',
      'Alkaline Earth Metals': 'var(--ggui-color-warning-500, #f59e0b)',
      'Transition Metals': 'var(--ggui-color-primary-500, #0ea5e9)',
      'Lanthanides': 'var(--ggui-color-primary-300, #7dd3fc)',
      'Actinides': 'var(--ggui-color-warning-600, #d97706)',
      'Post-Transition Metals': 'var(--ggui-color-primary-400, #38bdf8)',
      'Metalloids': 'var(--ggui-color-neutral-400, #9ca3af)',
      'Nonmetals': 'var(--ggui-color-success-500, #22c55e)',
      'Halogens': 'var(--ggui-color-success-600, #16a34a)',
      'Noble Gases': 'var(--ggui-color-primary-600, #0284c7)',
    };
    return colorMap[category ?? ''] ?? 'var(--ggui-color-neutral-200, #e5e7eb)';
  };

  const filteredElements = elements.filter((el) => {
    if (!searchTerm.trim()) return true;
    const term = searchTerm.toLowerCase();
    return (
      (el.name?.toLowerCase().includes(term) ?? false) ||
      (el.symbol?.toLowerCase().includes(term) ?? false)
    );
  });

  const categories = Array.from(
    new Set(elements.map((el) => el.category).filter(Boolean))
  ).sort() as string[];

  const handleElementClick = (element: Element) => {
    setSelectedElement(element);
  };

  const handleKeyDown = (
    e: React.KeyboardEvent<HTMLDivElement>,
    element: Element
  ) => {
    if (e.key === 'Enter' || e.key === ' ') {
      e.preventDefault();
      handleElementClick(element);
    }
  };

  return (
    <Container maxWidth="full" padding="24">
      <Stack direction="vertical" gap={16}>
        <Stack direction="vertical" gap={12}>
          <h1 style={{
            fontSize: 'var(--ggui-font-size-4xl, 36px)',
            fontWeight: 'var(--ggui-font-weight-bold, 700)',
            color: 'var(--ggui-color-onSurface, #18181b)',
            margin: 0,
          }}>
            Periodic Table of Elements
          </h1>
          <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Search, explore, and discover the elements
          </Text>
        </Stack>

        <Row gap={16} justify="between" align="start">
          <Input
            label="Search"
            placeholder="Search by name or symbol..."
            value={searchTerm}
            onChange={setSearchTerm}
          />

          <Stack direction="vertical" gap={8}>
            <Text variant="label" weight="semibold">
              Categories
            </Text>
            <Row gap={12} wrap>
              {categories.map((category) => (
                <Row
                  key={category}
                  gap={6}
                  align="center"
                  style={{ minWidth: 'fit-content' }}
                >
                  <div
                    style={{
                      width: '16px',
                      height: '16px',
                      borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                      backgroundColor: getCategoryColor(category),
                    }}
                  />
                  <Text variant="caption">{category}</Text>
                </Row>
              ))}
            </Row>
          </Stack>
        </Row>

        <Divider />

        <div
          style={{
            overflowX: 'auto',
            paddingBottom: 'var(--ggui-spacing-1, 4px)',
          }}
        >
          <div
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(18, minmax(70px, 1fr))',
              gap: 'var(--ggui-spacing-2, 8px)',
              width: '100%',
              minWidth: 'fit-content',
            }}
          >
            {filteredElements.length > 0 ? (
              filteredElements.map((element) => (
                <div
                  key={`${element.atomicNumber}-${element.symbol}`}
                  style={{
                    gridRow: element.row,
                    gridColumn: element.col,
                    border:
                      selectedElement?.atomicNumber === element.atomicNumber
                        ? '2px solid var(--ggui-color-primary-600, #0284c7)'
                        : '1px solid var(--ggui-color-outline, #d4d4d8)',
                    borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                    padding: 'var(--ggui-spacing-2, 8px)',
                    display: 'flex',
                    flexDirection: 'column',
                    justifyContent: 'center',
                    alignItems: 'center',
                    position: 'relative',
                    cursor: 'pointer',
                    transition: 'all 200ms cubic-bezier(0.4, 0, 0.2, 1)',
                    minHeight: '80px',
                    boxShadow:
                      selectedElement?.atomicNumber === element.atomicNumber
                        ? '0 0 0 3px var(--ggui-color-primary-100, #e0f2fe)'
                        : undefined,
                    backgroundColor: `color-mix(in srgb, ${getCategoryColor(
                      element.category
                    )} 85%, white)`,
                  }}
                  onClick={() => handleElementClick(element)}
                  onKeyDown={(e) => handleKeyDown(e, element)}
                  role="button"
                  tabIndex={0}
                  aria-label={`Element ${element.symbol}: ${element.name}`}
                  onMouseEnter={(e) => {
                    if (selectedElement?.atomicNumber !== element.atomicNumber) {
                      (e.currentTarget as HTMLElement).style.boxShadow =
                        'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))';
                      (e.currentTarget as HTMLElement).style.transform = 'scale(1.02)';
                    }
                  }}
                  onMouseLeave={(e) => {
                    if (selectedElement?.atomicNumber !== element.atomicNumber) {
                      (e.currentTarget as HTMLElement).style.boxShadow = 'none';
                      (e.currentTarget as HTMLElement).style.transform = 'scale(1)';
                    }
                  }}
                >
                  <div
                    style={{
                      position: 'absolute',
                      top: 'var(--ggui-spacing-1, 4px)',
                      left: 'var(--ggui-spacing-1, 4px)',
                      fontSize: 'var(--ggui-font-size-xs, 12px)',
                      color: 'var(--ggui-color-onSurfaceVariant, #52525b)',
                      fontWeight: 'var(--ggui-font-weight-medium, 500)',
                    }}
                  >
                    {element.atomicNumber}
                  </div>

                  <div style={{
                    fontSize: 'var(--ggui-font-size-2xl, 24px)',
                    fontWeight: 'var(--ggui-font-weight-bold, 700)',
                    color: 'var(--ggui-color-onSurface, #18181b)',
                    textAlign: 'center',
                  }}>
                    {element.symbol}
                  </div>

                  <Text
                    variant="caption"
                    align="center"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  >
                    {element.name}
                  </Text>
                </div>
              ))
            ) : (
              <Text
                variant="body"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
                style={{ gridColumn: '1 / -1', textAlign: 'center', padding: 'var(--ggui-spacing-6, 24px)' }}
              >
                No elements match your search.
              </Text>
            )}
          </div>
        </div>

        <Divider />

        <Card padding="16" shadow="md">
          {selectedElement ? (
            <Stack direction="vertical" gap={12}>
              <h2 style={{
                fontSize: 'var(--ggui-font-size-3xl, 30px)',
                fontWeight: 'var(--ggui-font-weight-bold, 700)',
                color: 'var(--ggui-color-onSurface, #18181b)',
                margin: 0,
              }}>
                {selectedElement.name}
              </h2>

              <Row gap={32} wrap>
                <div>
                  <Text
                    variant="label"
                    weight="semibold"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  >
                    Symbol
                  </Text>
                  <div style={{
                    fontSize: 'var(--ggui-font-size-2xl, 24px)',
                    fontWeight: 'var(--ggui-font-weight-bold, 700)',
                    color: 'var(--ggui-color-onSurface, #18181b)',
                  }}>
                    {selectedElement.symbol}
                  </div>
                </div>

                <div>
                  <Text
                    variant="label"
                    weight="semibold"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  >
                    Atomic Number
                  </Text>
                  <Text
                    variant="body"
                    color="var(--ggui-color-onSurface, #18181b)"
                  >
                    {selectedElement.atomicNumber}
                  </Text>
                </div>

                <div>
                  <Text
                    variant="label"
                    weight="semibold"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  >
                    Atomic Weight
                  </Text>
                  <Text
                    variant="body"
                    color="var(--ggui-color-onSurface, #18181b)"
                  >
                    {selectedElement.atomicWeight
                      ? selectedElement.atomicWeight.toFixed(2)
                      : 'N/A'}
                  </Text>
                </div>

                <div>
                  <Text
                    variant="label"
                    weight="semibold"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  >
                    Category
                  </Text>
                  <Row gap={8} align="center">
                    <div
                      style={{
                        width: '12px',
                        height: '12px',
                        borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                        backgroundColor: getCategoryColor(selectedElement.category),
                      }}
                    />
                    <Text
                      variant="body"
                      color="var(--ggui-color-onSurface, #18181b)"
                    >
                      {selectedElement.category || 'Unknown'}
                    </Text>
                  </Row>
                </div>
              </Row>
            </Stack>
          ) : (
            <Text
              variant="body"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
              align="center"
              style={{ padding: 'var(--ggui-spacing-6, 24px) 0' }}
            >
