            </Text>
          )}
        </Card>
      </Stack>
    </Container>
  );
}

import { useState, useEffect, useRef } from 'react';
import {
  Stack,
  Card,
  Text,
  Input,
  Button,
  Badge,
  Box,
  Icon,
} from '@ggui-ai/design/primitives';

interface Props {
  title?: string;
  currentUser?: string;
  participantCount?: number;
  messages?: Array<{ sender?: string; text?: string; timestamp?: string }>;
  onSend?: (payload: { text: string; timestamp: string }) => void;
  onSendMessage?: (payload: { text: string; timestamp: string }) => void;
}

export default function ChatInterface({
  title = 'Chat',
  currentUser = 'You',
  participantCount,
  messages = [],
  onSend,
  onSendMessage,
}: Props) {
  const [inputText, setInputText] = useState('');
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSendMessage = () => {
    if (inputText.trim()) {
      const payload = {
        text: inputText,
        timestamp: new Date().toISOString(),
      };
      onSend?.(payload);
      onSendMessage?.(payload);
      setInputText('');
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  const groupedMessages = messages.reduce(
    (groups, msg) => {
      const lastGroup = groups[groups.length - 1];
      if (lastGroup && lastGroup[0]?.sender === msg.sender) {
        lastGroup.push(msg);
      } else {
        groups.push([msg]);
      }
      return groups;
    },
    [] as Array<Array<(typeof messages)[0]>>
  );

  return (
    <Card
      padding={0}
      shadow="md"
      style={{
        display: 'flex',
        flexDirection: 'column',
        height: '100%',
        minHeight: '600px',
        backgroundColor: 'var(--ggui-color-surface, #fafafa)',
      }}
    >
      <div
        style={{
          backgroundColor: 'var(--ggui-color-container, #ede9fe)',
          padding: 'var(--ggui-spacing-4, 16px)',
          borderBottom: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
          gap: 'var(--ggui-spacing-2, 8px)',
        }}
      >
        <Text
          variant="label"
          color="var(--ggui-color-onContainer, #4c1d95)"
          weight="semibold"
        >
          {title}
        </Text>
        {participantCount !== undefined && (
          <Badge variant="primary" size="sm">
            {participantCount} {participantCount === 1 ? 'participant' : 'participants'}
          </Badge>
        )}
      </div>

      <div
        style={{
          flex: 1,
          overflowY: 'auto',
          padding: 'var(--ggui-spacing-4, 16px)',
          display: 'flex',
          flexDirection: 'column',
          gap: 'var(--ggui-spacing-4, 16px)',
          scrollBehavior: 'smooth',
        }}
        role="region"
        aria-label="Chat conversation"
        aria-live="polite"
      >
        {groupedMessages.length === 0 ? (
          <div
            style={{
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              height: '100%',
              color: 'var(--ggui-color-onSurfaceVariant, #52525b)',
            }}
          >
            <Text variant="caption" align="center">
              No messages yet. Start the conversation!
            </Text>
          </div>
        ) : (
          groupedMessages.map((group, groupIdx) => (
            <Stack
              key={groupIdx}
              direction="vertical"
              gap={2}
              align={group[0]?.sender === currentUser ? 'end' : 'start'}
            >
              {group[0]?.sender !== currentUser && (
                <Text
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  weight="medium"
                >
                  {group[0]?.sender || 'Unknown'}
                </Text>
              )}

              <Stack direction="vertical" gap={2}>
                {group.map((msg, msgIdx) => {
                  const isCurrentUser = msg.sender === currentUser;
                  const isLastInGroup = msgIdx === group.length - 1;
                  const timestamp = msg.timestamp
                    ? new Date(msg.timestamp).toLocaleTimeString([], {
                        hour: '2-digit',
                        minute: '2-digit',
                      })
                    : '';

                  return (
                    <Box
                      key={msgIdx}
                      padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)"
                      borderRadius="var(--ggui-shape-radius-md, 8px)"
                      background={
                        isCurrentUser
                          ? 'var(--ggui-color-primary-600, #0284c7)'
                          : 'var(--ggui-color-surfaceVariant, #f4f4f5)'
                      }
                      style={{
                        maxWidth: '70%',
                        wordWrap: 'break-word',
                        wordBreak: 'break-word',
                      }}
                    >
                      <Stack direction="vertical" gap={4}>
                        <Text
                          variant="body"
                          color={
                            isCurrentUser
                              ? 'var(--ggui-color-primary-50, #f0f9ff)'
                              : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                          }
                        >
                          {msg.text}
                        </Text>

                        {isLastInGroup && timestamp && (
                          <Text
                            variant="caption"
                            color={
                              isCurrentUser
                                ? 'var(--ggui-color-primary-100, #e0f2fe)'
                                : 'var(--ggui-color-onSurfaceVariant, #52525b)'
                            }
                            align={isCurrentUser ? 'right' : 'left'}
                          >
                            <time dateTime={msg.timestamp}>{timestamp}</time>
                          </Text>
                        )}
                      </Stack>
                    </Box>
                  );
                })}
              </Stack>
            </Stack>
          ))
        )}

        <div ref={messagesEndRef} />
      </div>

      <div
        style={{
          borderTop: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
          padding: 'var(--ggui-spacing-4, 16px)',
          backgroundColor: 'var(--ggui-color-surface, #fafafa)',
          display: 'flex',
          gap: 'var(--ggui-spacing-2, 8px)',
          alignItems: 'flex-end',
        }}
      >
        <Input
          label="Message"
          placeholder="Type a message..."
          value={inputText}
          onChange={setInputText}
          onKeyDown={handleKeyDown}
          type="text"
          style={{ flex: 1 }}
        />
        <Button
          variant="primary"
          size="sm"
          onClick={handleSendMessage}
          disabled={inputText.trim() === ''}
          rightIcon={<Icon name="plus" size={16} />}
          aria-label="Send message"
        >
          Send
        </Button>
      </div>
    </Card>
  );
}

import { useState, useEffect } from 'react';
import { Container, Card, Stack, Row, Text, Heading, MotionKeyframes, useMotion } from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface StockData {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<StockData>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

interface StockCardProps extends StockData {
  index: number;
}

function StockCard({ symbol, name, price, change, changePercent, index }: StockCardProps) {
  const { motionEnabled } = useMotion();

  // Determine change direction for color and styling
  const isPositive = change !== undefined && change > 0;
  const isNegative = change !== undefined && change < 0;
  const isNeutral = !isPositive && !isNegative;

  // Get border color based on change
  let borderColor = 'var(--ggui-color-outline, #d4d4d8)';
  let textColor = 'var(--ggui-color-onSurface, #18181b)';

  if (isPositive) {
    borderColor = 'var(--ggui-color-success-500, #22c55e)';
    textColor = 'var(--ggui-color-success-600, #16a34a)';
  } else if (isNegative) {
    borderColor = 'var(--ggui-color-error-500, #ef4444)';
    textColor = 'var(--ggui-color-error-600, #dc2626)';
  }

  const formattedPrice = price !== undefined && price !== null
    ? new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD', minimumFractionDigits: 2, maximumFractionDigits: 2 }).format(price)
    : 'N/A';

  const formattedChangePercent = changePercent !== undefined && changePercent !== null
    ? `${changePercent >= 0 ? '+' : ''}${changePercent.toFixed(2)}%`
    : '—';

  const arrowIcon = isPositive ? '▲' : isNegative ? '▼' : '—';

  const cardStyle: React.CSSProperties = {
    borderLeft: `3px solid ${borderColor}`,
    animation: motionEnabled ? `${animation.slideInUp}` : 'none',
    animationDelay: motionEnabled ? `${index * 50}ms` : '0ms',
    transition: 'border-color 200ms ease-out, box-shadow 200ms ease-out',
  };

  const changeStyle: React.CSSProperties = {
    color: isNeutral ? 'var(--ggui-color-onSurfaceVariant, #52525b)' : textColor,
    transition: 'color 200ms ease-out',
  };

  return (
    <Card
      padding="16"
      shadow="sm"
      border={false}
      style={cardStyle}
    >
      <Stack direction="vertical" gap={12}>
        {/* Symbol and Company Name Row */}
        <Row align="center" justify="between" gap={8}>
          <Stack direction="vertical" gap={4}>
            <Heading
              level={3}
              style={{
                fontSize: 'var(--ggui-font-size-xl, 20px)',
                fontWeight: 'var(--ggui-font-weight-bold, 700)',
                color: 'var(--ggui-color-onSurface, #18181b)',
                margin: 0,
              }}
            >
              {symbol || '—'}
            </Heading>
            <Text
              variant="body"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              {name || '—'}
            </Text>
          </Stack>
        </Row>

        {/* Price Display */}
        <Heading
          level={2}
          style={{
            fontSize: 'var(--ggui-font-size-2xl, 24px)',
            fontWeight: 'var(--ggui-font-weight-bold, 700)',
            color: 'var(--ggui-color-onSurface, #18181b)',
            margin: 0,
          }}
        >
          {formattedPrice}
        </Heading>

        {/* Change Row: Arrow, Amount, Percent */}
        <Row align="center" gap={8}>
          <Text
            variant="body"
            weight="bold"
            style={{
              ...changeStyle,
              fontSize: 'var(--ggui-font-size-lg, 18px)',
            }}
          >
            {arrowIcon}
          </Text>
          <Text
            variant="body"
            weight="semibold"
            style={changeStyle}
          >
            ${Math.abs(change ?? 0).toFixed(2)}
          </Text>
          <Text
            variant="body"
            weight="semibold"
            style={changeStyle}
          >
            {formattedChangePercent}
          </Text>
        </Row>
      </Stack>
    </Card>
  );
}

export default function StockTickerDashboard({
  stocks = [],
  lastUpdated,
}: Props) {
  const [displayedStocks, setDisplayedStocks] = useState<StockData[]>(stocks);
  const [connectionStatus, setConnectionStatus] = useState<'connected' | 'connecting' | 'disconnected'>('connecting');
  const [lastUpdateTime, setLastUpdateTime] = useState<string | undefined>(lastUpdated);
  const { motionEnabled } = useMotion();

  // Update local state when stocks prop changes (for initial load)
  useEffect(() => {
    setDisplayedStocks(stocks);
    if (lastUpdated) {
      setLastUpdateTime(lastUpdated);
    }
    if (stocks.length > 0) {
      setConnectionStatus('connected');
    }
  }, [stocks, lastUpdated]);

  const formatTimestamp = (isoString?: string) => {
    if (!isoString) return 'Unknown';
    try {
      const date = new Date(isoString);
      return date.toLocaleTimeString('en-US', { 
        hour: 'numeric', 
        minute: '2-digit', 
        second: '2-digit',
        hour12: true 
      });
    } catch {
      return 'Invalid time';
    }
  };

  const connectionDot = connectionStatus === 'connected' ? '🟢' : connectionStatus === 'connecting' ? '🟡' : '🔴';
  const statusText = connectionStatus === 'connected' ? '' : ` (${connectionStatus})`;

  return (
    <>
      <MotionKeyframes />

      <Container maxWidth="lg" padding="24" center={true}>
        <Stack direction="vertical" gap={24}>
          {/* Header Section */}
          <Stack
            direction="vertical"
            gap={8}
            style={{
              backgroundColor: 'var(--ggui-color-container, #ede9fe)',
              padding: 'var(--ggui-spacing-4, 16px)',
              borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
              borderBottom: '2px solid var(--ggui-color-outline, #d4d4d8)',
            }}
          >
            <Heading
              level={1}
              style={{
                fontSize: 'var(--ggui-font-size-2xl, 24px)',
                fontWeight: 'var(--ggui-font-weight-bold, 700)',
                color: 'var(--ggui-color-onContainer, #4c1d95)',
                margin: 0,
              }}
            >
              Market Watch
            </Heading>
            <Text
              variant="caption"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              {connectionDot} Last Updated: {formatTimestamp(lastUpdateTime)}{statusText}
            </Text>
          </Stack>

          {/* Stock Grid */}
          {displayedStocks.length === 0 ? (
            <Card padding="32" shadow="sm" border={true}>
              <Stack direction="vertical" gap={8} align="center" justify="center">
                <Text
                  variant="body"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  align="center"
                >
                  No stocks available. Waiting for data...
                </Text>
              </Stack>
            </Card>
          ) : (
            <div
              style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
                gap: 'var(--ggui-spacing-4, 16px)',
                width: '100%',
              }}
            >
              {displayedStocks.map((stock, index) => (
                <div
                  key={stock.symbol || `stock-${index}`}
                  role="article"
                  aria-label={`${stock.symbol || 'Stock'} - ${stock.name || 'Company'}`}
                >
                  <StockCard
                    symbol={stock.symbol}
                    name={stock.name}
                    price={stock.price}
                    change={stock.change}
                    changePercent={stock.changePercent}
                    index={index}
                  />
                </div>
              ))}
            </div>
          )}

          {/* Footer Note */}
          <Text
            variant="caption"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
            align="center"
          >
            Real-time data updates via live broadcast
          </Text>
        </Stack>
      </Container>
    </>
  );
}

