export default function OnboardingWizard({
  initialProfile,
  avatarOptions,
  roleOptions,
  onComplete,
}: Props) {
  const { motionEnabled } = useMotion();
  const [currentStep, setCurrentStep] = useState(0);
  const [profile, setProfile] = useState<Profile>({
    name: initialProfile?.name ?? '',
    email: initialProfile?.email ?? '',
    avatar: initialProfile?.avatar ?? avatarOptions[0] ?? '',
    role: initialProfile?.role ?? '',
    emailNotifications: initialProfile?.emailNotifications ?? false,
    theme: initialProfile?.theme ?? 'light',
  });

  const [errors, setErrors] = useState<Record<string, string>>({});
  const [isSubmitting, setIsSubmitting] = useState(false);

  useEffect(() => {
    if (!profile.avatar && avatarOptions.length > 0) {
      setProfile(prev => ({ ...prev, avatar: avatarOptions[0] }));
    }
  }, [avatarOptions, profile.avatar]);

  const validateEmail = (email: string): string => {
    if (!email) return 'Email is required';
    if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
      return 'Please enter a valid email address';
    }
    return '';
  };

  const validateName = (name: string): string => {
    if (!name || name.trim() === '') return 'Name is required';
    return '';
  };

  const validateStep1 = (): boolean => {
    const nameError = validateName(profile.name);
    const emailError = validateEmail(profile.email);
    const newErrors: Record<string, string> = {};
    if (nameError) newErrors.name = nameError;
    if (emailError) newErrors.email = emailError;
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const updateField = (field: keyof Profile, value: string | boolean) => {
    setProfile(prev => ({ ...prev, [field]: value }));
    setErrors(prev => {
      const newErrors = { ...prev };
      delete newErrors[field];
      return newErrors;
    });
  };

  const handleNext = () => {
    if (currentStep === 0 && !validateStep1()) return;
    if (currentStep < STEP_NAMES.length - 1) {
      setCurrentStep(currentStep + 1);
    }
  };

  const handleBack = () => {
    if (currentStep > 0) {
      setCurrentStep(currentStep - 1);
      setErrors({});
    }
  };

  const handleComplete = async () => {
    setIsSubmitting(true);
    try {
      if (onComplete) {
        await onComplete(profile);
      }
    } finally {
      setIsSubmitting(false);
    }
  };

  const renderContent = () => {
    const contentStyle = { animation: motionEnabled ? animation.slideInUp : 'none' };
    const contentProps = { profile, errors, updateField, avatarOptions, roleOptions };

    switch (currentStep) {
      case 0:
        return <div style={contentStyle}><Step1Content {...contentProps} /></div>;
      case 1:
        return <div style={contentStyle}><Step2Content {...contentProps} /></div>;
      case 2:
        return <div style={contentStyle}><Step3Content {...contentProps} /></div>;
      default:
        return null;
    }
  };

  return (
    <>
      <MotionKeyframes />
      <Container maxWidth="md" center={true} padding={24}>
        <Stack direction="vertical" gap={24}>
          <StepIndicator currentStep={currentStep} />
          <Divider orientation="horizontal" margin={0} />
          {renderContent()}
          <Divider orientation="horizontal" margin={0} />
          <Row gap={16} justify="between" align="center">
            {currentStep > 0 ? (
              <Button variant="outline" size="md" onClick={handleBack} aria-label="Go back to previous step">
                ← Go Back
              </Button>
            ) : (
              <div />
            )}
            {currentStep < STEP_NAMES.length - 1 ? (
              <Button
                variant="primary"
                size="md"
                onClick={handleNext}
                disabled={isSubmitting}
                rightIcon={<Icon name="chevron-right" size={16} />}
              >
                Next Step
              </Button>
            ) : (
              <Button
                variant="primary"
                size="md"
                onClick={handleComplete}
                loading={isSubmitting}
                disabled={isSubmitting}
                leftIcon={!isSubmitting ? <Icon name="check" size={16} /> : undefined}
              >
                {isSubmitting ? 'Completing...' : 'Complete Setup'}
              </Button>
            )}
          </Row>
        </Stack>
      </Container>
    </>
  );
}

