import { useEffect, useMemo, useState } from 'react';
import {
  Container,
  MotionKeyframes,
  useMotion,
  Stack,
  Row,
  Card,
  Text,
  Badge,
  Button,
  Input,
  Select,
  Icon,
  Divider,
  Toast,
  Box,
} from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

interface Props {
  /** Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate */
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>;
  /** Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}] */
  columns: Array<{ id?: string; name?: string }>;
  onSubmit?: (payload: {
    action: 'move' | 'edit' | 'create';
    taskId: string;
    data: Record<string, unknown>;
  }) => Promise<void> | void;
}

type TaskItem = Props['tasks'][number];

const defaultColumns: Props['columns'] = [
  { id: 'todo', name: 'To Do' },
  { id: 'in-progress', name: 'In Progress' },
  { id: 'done', name: 'Done' },
];

export default function GeneratedComponent({
  tasks = [],
  columns = defaultColumns,
  onSubmit,
}: Props) {
  const { motionEnabled } = useMotion();

  const [localTasks, setLocalTasks] = useState<TaskItem[]>(tasks);
  const [addingColumnId, setAddingColumnId] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [newTaskErrors, setNewTaskErrors] = useState<{ title?: string; priority?: string; submit?: string }>({});
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editTitle, setEditTitle] = useState('');
  const [editErrors, setEditErrors] = useState<{ title?: string }>({});
  const [movePendingTaskId, setMovePendingTaskId] = useState<string | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [feedback, setFeedback] = useState<{ type: 'success' | 'error'; message: string; visible: boolean }>({
    type: 'success',
    message: '',
    visible: false,
  });

  useEffect(() => {
    setLocalTasks(tasks);
  }, [tasks]);

  const doneColumnId = useMemo(
    () => columns.find((c) => (c.id || '').toLowerCase() === 'done')?.id || 'done',
    [columns]
  );

  const totalTasks = localTasks.length;
  const completedCount = localTasks.filter((t) => t.column === doneColumnId).length;

  const validateTitle = (value: string) => {
    const v = value.trim();
    if (!v) return 'Title is required';
    if (v.length < 2) return 'Title must be at least 2 characters';
    return '';
  };

  const getPriorityBadgeVariant = (priority?: 'low' | 'medium' | 'high') => {
    if (priority === 'high') return 'error';
    if (priority === 'medium') return 'warning';
    return 'secondary';
  };

  const openAddForm = (columnId?: string) => {
    setAddingColumnId(columnId || null);
    setNewTaskTitle('');
    setNewTaskPriority('medium');
    setNewTaskErrors({});
  };

  const handleCreateTask = async () => {
    const titleErr = validateTitle(newTaskTitle);
    const priorityErr = !newTaskPriority ? 'Priority is required' : '';
    if (titleErr || priorityErr) {
      setNewTaskErrors({ title: titleErr, priority: priorityErr });
      return;
    }

    const newId = `task-${Date.now()}`;
    const todoId = columns.find((c) => c.id === 'todo')?.id || 'todo';
    const payloadData = {
      title: newTaskTitle.trim(),
      priority: newTaskPriority,
      assignee: '',
      column: todoId,
      dueDate: '',
    };

    setIsSubmitting(true);
    setNewTaskErrors({});
    try {
      await onSubmit?.({ action: 'create', taskId: newId, data: payloadData });
      setLocalTasks((prev) => [...prev, { id: newId, ...payloadData }]);
      setFeedback({ type: 'success', message: 'Task created successfully', visible: true });
      setAddingColumnId(null);
      setNewTaskTitle('');
      setNewTaskPriority('medium');
    } catch {
      setFeedback({ type: 'error', message: 'Failed to create task', visible: true });
      setNewTaskErrors((prev) => ({ ...prev, submit: 'Unable to submit task update.' }));
    } finally {
      setIsSubmitting(false);
    }
  };

  const startEdit = (task: TaskItem) => {
    setEditingTaskId(task.id || null);
    setEditTitle(task.title || '');
    setEditErrors({});
  };

  const cancelEdit = () => {
    setEditingTaskId(null);
    setEditTitle('');
    setEditErrors({});
  };

  const saveEdit = async (task: TaskItem) => {
    const taskId = task.id || '';
    const titleErr = validateTitle(editTitle);
    if (titleErr) {
      setEditErrors({ title: titleErr });
      return;
    }

    const prevTasks = localTasks;
    const nextTasks = localTasks.map((t) => (t.id === taskId ? { ...t, title: editTitle.trim() } : t));
    setLocalTasks(nextTasks);

    try {
      await onSubmit?.({ action: 'edit', taskId, data: { title: editTitle.trim() } });
      setFeedback({ type: 'success', message: 'Task updated', visible: true });
      cancelEdit();
    } catch {
      setLocalTasks(prevTasks);
      setFeedback({ type: 'error', message: 'Failed to update task', visible: true });
    }
  };

  const handleMoveTask = async (task: TaskItem, targetColumnId: string) => {
    const taskId = task.id || '';
    const previousColumn = task.column || '';
    if (!targetColumnId || targetColumnId === previousColumn) return;

    setMovePendingTaskId(taskId);
    setLocalTasks((prev) => prev.map((t) => (t.id === taskId ? { ...t, column: targetColumnId } : t)));

    try {
      await onSubmit?.({ action: 'move', taskId, data: { column: targetColumnId } });
      setFeedback({ type: 'success', message: 'Task moved', visible: true });
    } catch {
      setLocalTasks((prev) => prev.map((t) => (t.id === taskId ? { ...t, column: previousColumn } : t)));
      setFeedback({ type: 'error', message: 'Failed to move task', visible: true });
    } finally {
      setMovePendingTaskId(null);
    }
  };

  return (
    <Container maxWidth="full" padding={24}>
      <MotionKeyframes />
      <Stack gap={24}>
        <Card
          shadow="sm"
          border
          padding={16}
          style={{
            background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            borderColor: 'var(--ggui-color-outline, #d4d4d8)',
            transition: transition.colors,
          }}
        >
          <Row justify="between" align="center">
            <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
              Total Tasks: {totalTasks}
            </Text>
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Completed: {completedCount}
            </Text>
          </Row>
        </Card>

        <Divider />

        <Row gap={16} align="start" wrap>
          {columns.map((column, columnIndex) => {
            const columnId = column.id || '';
            const columnName = column.name || '';
            const headerId = `column-header-${columnId || columnIndex}`;
            const columnTasks = localTasks.filter((t) => t.column === columnId);

            return (
              <Card
                key={columnId || columnIndex}
                padding={16}
                shadow="sm"
                border
                role="section"
                aria-labelledby={headerId}
                style={{
                  minWidth: '280px',
                  flex: '1 1 280px',
                  background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                  borderColor: 'var(--ggui-color-outline, #d4d4d8)',
                  borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                  animation: motionEnabled ? animation.slideInUp : 'none',
                  transition: transition.colors,
                }}
              >
                <Stack gap={12}>
                  <Row justify="between" align="center">
                    <Text id={headerId} variant="h3" color="var(--ggui-color-onSurface, #18181b)">
                      {columnName}
                    </Text>
                    <Badge variant="info" size="sm">
                      {columnTasks.length}
                    </Badge>
                  </Row>

                  <Stack gap={8} role="list" aria-label={`${columnName} task list`}>
                    {columnTasks.map((task) => {
                      const isEditing = editingTaskId === (task.id || '');
                      return (
                        <Card
                          key={task.id || `${columnId}-${task.title}`}
                          padding={12}
                          shadow="none"
                          border
                          role="listitem"
                          style={{
                            background: 'var(--ggui-color-surface, #fafafa)',
                            borderColor: 'var(--ggui-color-outlineVariant, #e4e4e7)',
                            animation: motionEnabled ? animation.slideInUp : 'none',
                            transition: `${transition.colors}, ${transition.transform}`,
                          }}
                        >
                          <Stack gap={8}>
                            <Row justify="between" align="start">
                              {isEditing ? (
                                <Input
                                  label="Task title"
                                  value={editTitle}
                                  onChange={setEditTitle}
                                  error={editErrors.title}
                                />
                              ) : (
                                <Text
                                  variant="body"
                                  color="var(--ggui-color-onSurface, #18181b)"
                                  onDoubleClick={() => startEdit(task)}
                                >
                                  {task.title || 'Untitled Task'}
                                </Text>
                              )}

                              {!isEditing ? (
                                <Button
                                  variant="ghost"
                                  size="xs"
                                  aria-label={`Edit task ${task.title || ''}`}
                                  onClick={() => startEdit(task)}
                                  leftIcon={<Icon name="chevron-down" size={14} />}
                                >
                                  Edit
                                </Button>
                              ) : (
                                <Row gap={6}>
                                  <Button
                                    variant="primary"
                                    size="xs"
                                    onClick={() => saveEdit(task)}
                                    leftIcon={<Icon name="check" size={14} />}
                                  >
                                    Save
                                  </Button>
                                  <Button
                                    variant="outline"
                                    size="xs"
                                    onClick={cancelEdit}
                                    leftIcon={<Icon name="x" size={14} />}
                                  >
                                    Cancel
                                  </Button>
                                </Row>
                              )}
                            </Row>

                            <Row gap={8} align="center" wrap>
                              <Badge variant={getPriorityBadgeVariant(task.priority)} size="sm">
                                {task.priority || 'low'}
                              </Badge>

                              <Box
                                style={{
                                  width: '28px',
                                  height: '28px',
                                  borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                                  border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                                  display: 'flex',
                                  alignItems: 'center',
                                  justifyContent: 'center',
                                  background: 'var(--ggui-color-container, #ede9fe)',
                                  color: 'var(--ggui-color-onContainer, #4c1d95)',
                                }}
                              >
                                {task.assignee ? (
                                  <Text variant="caption">{task.assignee}</Text>
                                ) : (
                                  <Icon name="user" size={14} color="var(--ggui-color-onContainer, #4c1d95)" />
                                )}
                              </Box>

                              {task.dueDate ? (
                                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                                  Due: {task.dueDate}
                                </Text>
                              ) : null}
                            </Row>

                            <Row justify="between" align="center">
                              <Select
                                label="Move task"
                                value={task.column || ''}
                                onChange={(value) => handleMoveTask(task, value)}
                                disabled={movePendingTaskId === (task.id || '')}
                                options={columns.map((c) => ({
                                  value: c.id || '',
                                  label: c.name || '',
                                  disabled: c.id === task.column,
                                }))}
                              />
                            </Row>
                          </Stack>
                        </Card>
                      );
                    })}
                  </Stack>

                  {addingColumnId !== columnId ? (
                    <Button
                      variant="outline"
                      size="sm"
                      leftIcon={<Icon name="plus" size={14} />}
                      onClick={() => openAddForm(columnId)}
                    >
                      Add Task
                    </Button>
                  ) : (
                    <Card
                      padding={12}
                      border
                      shadow="none"
                      style={{
                        background: 'var(--ggui-color-surface, #fafafa)',
                        borderColor: 'var(--ggui-color-outlineVariant, #e4e4e7)',
                      }}
                    >
                      <Stack gap={8}>
                        <Input
                          label="Task title"
                          value={newTaskTitle}
                          onChange={setNewTaskTitle}
                          error={newTaskErrors.title}
                          placeholder="Enter task title"
                        />
                        <Select
                          label="Priority"
                          value={newTaskPriority}
                          onChange={(v) => setNewTaskPriority(v as 'low' | 'medium' | 'high')}
                          options={[
                            { value: 'low', label: 'Low' },
                            { value: 'medium', label: 'Medium' },
                            { value: 'high', label: 'High' },
                          ]}
                          error={newTaskErrors.priority}
                        />
                        {newTaskErrors.submit ? (
                          <Text variant="caption" color="var(--ggui-color-error-600, #dc2626)">
                            {newTaskErrors.submit}
                          </Text>
                        ) : null}
                        <Row gap={8}>
                          <Button
                            variant="primary"
                            size="sm"
                            onClick={handleCreateTask}
                            loading={isSubmitting}
                            disabled={isSubmitting || !!validateTitle(newTaskTitle)}
                            leftIcon={<Icon name="check" size={14} />}
                          >
                            Submit
                          </Button>
                          <Button
                            variant="ghost"
                            size="sm"
                            onClick={() => setAddingColumnId(null)}
                            disabled={isSubmitting}
                            leftIcon={<Icon name="x" size={14} />}
                          >
                            Cancel
                          </Button>
                        </Row>
                      </Stack>
                    </Card>
                  )}
                </Stack>
              </Card>
            );
          })}
        </Row>

        <Toast
          visible={feedback.visible}
          variant={feedback.type}
          title={feedback.type === 'success' ? 'Success' : 'Error'}
          message={feedback.message}
          onClose={() => setFeedback((prev) => ({ ...prev, visible: false }))}
        />
      </Stack>
    </Container>
  );
}

import { useMemo, useState } from 'react';
import { Card, Stack, Text, Input, Button } from '@ggui-ai/design/primitives';

interface Props {
  /** Full periodic table element data */
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

export default function GeneratedComponent({
  elements = [],
}: Props) {
  const [search, setSearch] = useState('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | undefined>(undefined);

  const categoryColors: Record<string, string> = {
    'alkali metal': 'var(--ggui-color-error-500, #ef4444)',
    'alkaline earth metal': 'var(--ggui-color-warning-500, #f59e0b)',
    'transition metal': 'var(--ggui-color-primary-600, #0284c7)',
    'post-transition metal': 'var(--ggui-color-primary-400, #38bdf8)',
    metalloid: 'var(--ggui-color-success-500, #22c55e)',
    nonmetal: 'var(--ggui-color-success-600, #16a34a)',
    halogen: 'var(--ggui-color-warning-600, #d97706)',
    'noble gas': 'var(--ggui-color-primary-500, #0ea5e9)',
    lanthanide: 'var(--ggui-color-info-500, #06b6d4)',
    actinide: 'var(--ggui-color-neutral-600, #4b5563)',
    unknown: 'var(--ggui-color-neutral-400, #9ca3af)',
  };

  const normalized = (v?: string) => (v || '').trim().toLowerCase();

  const filteredElements = useMemo(() => {
    const q = search.trim().toLowerCase();
    if (!q) return elements;
    return elements.filter((el) => {
      const name = (el.name || '').toLowerCase();
      const symbol = (el.symbol || '').toLowerCase();
      return name.includes(q) || symbol.includes(q);
    });
  }, [elements, search]);

  const selected = useMemo(
    () => elements.find((el) => el.atomicNumber === selectedAtomicNumber),
    [elements, selectedAtomicNumber]
  );

  const categories = useMemo(() => {
    const set = new Set<string>();
    elements.forEach((el) => {
      const c = normalized(el.category) || 'unknown';
      set.add(c);
    });
    return Array.from(set).sort();
  }, [elements]);

  return (
    <Stack gap={16}>
      <Text variant="h2" color="var(--ggui-color-onSurface, #18181b)">
        Periodic Table
      </Text>

      <Input
        label="Search elements"
        placeholder="Filter by name or symbol..."
        value={search}
        onChange={setSearch}
      />

      <Card>
        <Stack gap={12}>
          <div
            role="grid"
            aria-label="Periodic table grid"
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(18, minmax(44px, 1fr))',
              gap: 'var(--ggui-spacing-2, 8px)',
              background: 'var(--ggui-color-surface, #fafafa)',
            }}
          >
            {filteredElements.map((el) => {
              const category = normalized(el.category) || 'unknown';
              const color = categoryColors[category] || 'var(--ggui-color-neutral-400, #9ca3af)';
              const isSelected = selectedAtomicNumber === el.atomicNumber;

              return (
                <Button
                  key={`${el.atomicNumber ?? 'x'}-${el.symbol ?? 'na'}-${el.row ?? 'r'}-${el.col ?? 'c'}`}
                  variant={isSelected ? 'primary' : 'outline'}
                  size="sm"
                  onClick={() => setSelectedAtomicNumber(el.atomicNumber)}
                >
                  <div
                    role="gridcell"
                    aria-label={`${el.name || 'Unknown'} (${el.symbol || '?'})`}
                    style={{
                      gridColumn: el.col ?? 'auto',
                      gridRow: el.row ?? 'auto',
                      width: '100%',
                      minHeight: '64px',
                      border: `1px solid var(--ggui-color-outline, #d4d4d8)`,
                      borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                      background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                      position: 'relative',
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      transition: 'transform 200ms ease, border-color 200ms ease',
                      boxShadow: isSelected ? `0 0 0 2px ${color}` : 'none',
                    }}
                  >
                    <Text
                      variant="caption"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                      style={{
                        position: 'absolute',
                        top: '6px',
                        left: '6px',
                      } as React.CSSProperties}
                    >
                      {el.atomicNumber ?? '—'}
                    </Text>
                    <Text
                      variant="h3"
                      color={color}
                      align="center"
                      weight="bold"
                    >
                      {el.symbol || '?'}
                    </Text>
                  </div>
                </Button>
              );
            })}
          </div>

          <Card border>
            <Stack gap={8}>
              <Text variant="h3">Element Details</Text>
              {selected ? (
                <Stack gap={4}>
                  <Text><strong>Name:</strong> {selected.name || '—'}</Text>
                  <Text><strong>Symbol:</strong> {selected.symbol || '—'}</Text>
                  <Text><strong>Atomic Number:</strong> {selected.atomicNumber ?? '—'}</Text>
                  <Text><strong>Atomic Weight:</strong> {selected.atomicWeight ?? '—'}</Text>
                  <Text><strong>Category:</strong> {selected.category || '—'}</Text>
                </Stack>
              ) : (
                <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Select an element to view details.
                </Text>
              )}
            </Stack>
          </Card>

          <Card border>
            <Stack gap={8}>
              <Text variant="h3">Legend</Text>
              <div
                style={{
                  display: 'grid',
                  gridTemplateColumns: 'repeat(auto-fit, minmax(180px, 1fr))',
                  gap: 'var(--ggui-spacing-2, 8px)',
                }}
              >
                {categories.map((cat) => {
                  const color = categoryColors[cat] || 'var(--ggui-color-neutral-400, #9ca3af)';
                  return (
                    <div
                      key={cat}
                      style={{
                        display: 'flex',
                        alignItems: 'center',
                        gap: 'var(--ggui-spacing-2, 8px)',
                        border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                        borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                        padding: 'var(--ggui-spacing-2, 8px)',
                        background: 'var(--ggui-color-surface, #fafafa)',
                      }}
                    >
                      <span
                        aria-hidden="true"
                        style={{
                          width: '12px',
                          height: '12px',
                          borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                          background: color,
                          display: 'inline-block',
                        }}
                      />
                      <Text variant="caption" color="var(--ggui-color-onSurface, #18181b)">
                        {cat}
                      </Text>
                    </div>
                  );
                })}
              </div>
            </Stack>
          </Card>
        </Stack>
      </Card>
    </Stack>
  );
}

import { useEffect, useMemo, useRef, useState } from 'react';
import { Card, Stack, Text, Button, Input, Badge } from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Action Contract: Send Message */
  sendMessage?: (payload: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent({
  title = '',
  currentUser = '',
  participantCount,
  messages = [],
  sendMessage,
}: Props) {
  const [draft, setDraft] = useState('');
  const [streamMessages, setStreamMessages] = useState<Array<{ sender?: string; text?: string; timestamp?: string }>>([]);
  const listRef = useRef<HTMLDivElement>(null);

  const allMessages = useMemo(() => [...messages, ...streamMessages], [messages, streamMessages]);

  const groupedMessages = useMemo(() => {
    const groups: Array<{ sender?: string; items: Array<{ sender?: string; text?: string; timestamp?: string }> }> = [];
    allMessages.forEach((msg) => {
      const last = groups[groups.length - 1];
      if (last && last.sender === msg.sender) {
        last.items.push(msg);
      } else {
        groups.push({ sender: msg.sender, items: [msg] });
      }
    });
    return groups;
  }, [allMessages]);

  const scrollToBottom = () => {
    if (listRef.current) {
      listRef.current.scrollTop = listRef.current.scrollHeight;
    }
  };

  useEffect(() => {
    scrollToBottom();
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [allMessages.length]);

  useEffect(() => {
    const handler = (event: Event) => {
      const customEvent = event as CustomEvent<{ sender?: string; text?: string; timestamp?: string }>;
      if (customEvent.detail) {
        setStreamMessages((prev) => [...prev, customEvent.detail]);
      }
    };

    window.addEventListener('ggui:agent-data', handler);
    return () => window.removeEventListener('ggui:agent-data', handler);
  }, []);

  const handleSend = () => {
    const text = draft.trim();
    if (!text) return;
    const timestamp = new Date().toISOString();
    sendMessage?.({ text, timestamp });
    setDraft('');
  };

  const formatTimestamp = (value?: string) => {
    if (!value) return '';
    const date = new Date(value);
    if (Number.isNaN(date.getTime())) return value;
    return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  };

  return (
    <Card padding={0} border shadow="sm">
      <Stack gap={0}>
        <Stack
          direction="horizontal"
          justify="between"
          align="center"
          gap={8}
          style={{
            padding: 'var(--ggui-spacing-4, 16px)',
            borderBottom: '1px solid var(--ggui-color-outline, #d4d4d8)',
            background: 'var(--ggui-color-surface, #fafafa)',
          }}
        >
          <Text variant="h3" color="var(--ggui-color-onSurface, #18181b)">
            {title}
          </Text>
          {participantCount !== undefined && (
            <Badge variant="primary" size="sm">
              {participantCount}
            </Badge>
          )}
        </Stack>

        <div
          ref={listRef}
          aria-label="Message list"
          style={{
            height: '320px',
            overflowY: 'auto',
            background: 'var(--ggui-color-surface, #fafafa)',
            padding: 'var(--ggui-spacing-4, 16px)',
          }}
        >
          <Stack gap={10}>
            {groupedMessages.map((group, groupIndex) => {
              const isOwn = (group.sender || '') === currentUser;
              return (
                <Stack
                  key={`${group.sender || 'unknown'}-${groupIndex}`}
                  gap={6}
                  align={isOwn ? 'end' : 'start'}
                >
                  {group.items.map((msg, msgIndex) => (
                    <Stack
                      key={`${groupIndex}-${msgIndex}-${msg.timestamp || ''}`}
                      gap={4}
                      style={{
                        maxWidth: '75%',
                        padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)',
                        borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                        background: isOwn
                          ? 'var(--ggui-color-primary-600, #0284c7)'
                          : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                        color: isOwn ? 'var(--ggui-color-surface, #fafafa)' : 'var(--ggui-color-onSurface, #18181b)',
                        border: isOwn ? 'none' : '1px solid var(--ggui-color-outline, #d4d4d8)',
                      }}
                    >
                      {msgIndex === 0 && (
                        <Text
                          variant="caption"
                          weight="semibold"
                          color={isOwn ? 'var(--ggui-color-surface, #fafafa)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}
                        >
                          {msg.sender || ''}
                        </Text>
                      )}
                      <Text
                        variant="body"
                        color={isOwn ? 'var(--ggui-color-surface, #fafafa)' : 'var(--ggui-color-onSurface, #18181b)'}
                      >
                        {msg.text || ''}
                      </Text>
                      <Text
                        variant="caption"
                        align="right"
                        color={isOwn ? 'var(--ggui-color-primary-100, #e0f2fe)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}
                      >
                        {formatTimestamp(msg.timestamp)}
                      </Text>
                    </Stack>
                  ))}
                </Stack>
              );
            })}
          </Stack>
        </div>

        <Stack
          direction="horizontal"
          gap={8}
          align="end"
          style={{
            padding: 'var(--ggui-spacing-4, 16px)',
            borderTop: '1px solid var(--ggui-color-outline, #d4d4d8)',
            background: 'var(--ggui-color-surface, #fafafa)',
          }}
        >
          <Input
            label="Message"
            placeholder="Type a message..."
            value={draft}
            onChange={setDraft}
            helperText="Press Enter to send"
          />
          <Button
            variant="primary"
            onClick={handleSend}
            disabled={!draft.trim()}
          >
            Send
          </Button>
        </Stack>
      </Stack>

      <input
        aria-hidden
        tabIndex={-1}
        style={{ position: 'absolute', opacity: 0, pointerEvents: 'none', width: 0, height: 0 }}
        onKeyDown={(e) => {
          if (e.key === 'Enter' && draft.trim()) {
            e.preventDefault();
            handleSend();
          }
        }}
      />
    </Card>
  );
}

import { useEffect, useMemo, useState } from 'react';
import { Card, Stack, Text } from '@ggui-ai/design/primitives';

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function GeneratedComponent(props: Props) {
  const [liveStocks, setLiveStocks] = useState<Props['stocks']>(props.stocks ?? []);
  const [liveLastUpdated, setLiveLastUpdated] = useState<string | undefined>(props.lastUpdated);
  const [isConnecting, setIsConnecting] = useState(true);
  const [isLive, setIsLive] = useState(false);

  useEffect(() => {
    setLiveStocks(props.stocks ?? []);
  }, [props.stocks]);

  useEffect(() => {
    setLiveLastUpdated(props.lastUpdated);
  }, [props.lastUpdated]);

  useEffect(() => {
    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent<Partial<Props>>;
      const detail = customEvent.detail ?? {};

      if (Array.isArray(detail.stocks)) {
        setLiveStocks(detail.stocks);
      }
      if (typeof detail.lastUpdated === 'string') {
        setLiveLastUpdated(detail.lastUpdated);
      }

      setIsConnecting(false);
      setIsLive(true);
    };

    const timer = window.setTimeout(() => {
      setIsConnecting(false);
    }, 1400);

    window.addEventListener('ggui:agent-data', handleAgentData as EventListener);
    return () => {
      window.removeEventListener('ggui:agent-data', handleAgentData as EventListener);
      window.clearTimeout(timer);
    };
  }, []);

  const formattedUpdated = useMemo(() => {
    if (!liveLastUpdated) return '—';
    const d = new Date(liveLastUpdated);
    if (Number.isNaN(d.getTime())) return liveLastUpdated;
    return d.toLocaleString();
  }, [liveLastUpdated]);

  return (
    <Stack gap={16}>
      <Card border shadow="sm" padding={16}>
        <Stack direction="horizontal" justify="between" align="center" wrap gap={8}>
          <Text variant="h2" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
            Market Watch
          </Text>
          <Stack direction="horizontal" gap={8} align="center">
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Last Updated:
            </Text>
            <Text variant="body" weight="medium" color="var(--ggui-color-onSurface, #18181b)">
              {formattedUpdated}
            </Text>
            <Text
              variant="caption"
              color={
                isConnecting
                  ? 'var(--ggui-color-warning-500, #f59e0b)'
                  : isLive
                  ? 'var(--ggui-color-success-500, #22c55e)'
                  : 'var(--ggui-color-onSurfaceVariant, #52525b)'
              }
            >
              {isConnecting ? 'Connecting…' : isLive ? 'Live' : 'Static'}
            </Text>
          </Stack>
        </Stack>
      </Card>

      <div
        role="list"
        aria-label="Stock ticker cards"
        style={{
          display: 'grid',
          gap: 'var(--ggui-spacing-4, 16px)',
          gridTemplateColumns: 'repeat(auto-fit, minmax(240px, 1fr))',
        }}
      >
        {liveStocks.map((stock) => {
          const symbol = stock.symbol ?? '—';
          const name = stock.name ?? 'Unknown company';
          const price = typeof stock.price === 'number' ? stock.price.toFixed(2) : '0.00';
          const change = typeof stock.change === 'number' ? stock.change : 0;
          const changePercent = typeof stock.changePercent === 'number' ? stock.changePercent : 0;
          const positive = change >= 0;
          const trendColor = positive
            ? 'var(--ggui-color-success-500, #22c55e)'
            : 'var(--ggui-color-error-500, #ef4444)';
          const arrow = positive ? '▲' : '▼';

          return (
            <Card
              key={`${symbol}-${name}`}
              border
              shadow="sm"
              padding={16}
            >
              <Stack
                gap={8}
                role="listitem"
                aria-label={`${symbol} ${name} price ${price}`}
              >
                <Text
                  variant="h1"
                  weight="bold"
                  color="var(--ggui-color-onSurface, #18181b)"
                >
                  {symbol}
                </Text>
                <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {name}
                </Text>
                <Text variant="h3" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  ${price}
                </Text>
                <Text variant="body" weight="medium" color={trendColor}>
                  {change >= 0 ? '+' : ''}
                  {change.toFixed(2)}
                </Text>
                <Text variant="body" weight="semibold" color={trendColor}>
                  {arrow} {changePercent >= 0 ? '+' : ''}
                  {changePercent.toFixed(2)}%
                </Text>
              </Stack>
              <div
                aria-hidden="true"
                style={{
                  marginTop: 'var(--ggui-spacing-2, 8px)',
                  borderTop: `1px solid var(--ggui-color-outline, #d4d4d8)`,
                }}
              />
              <div
                aria-hidden="true"
                style={{
                  marginTop: 'var(--ggui-spacing-2, 8px)',
                  border: `1px solid ${trendColor}`,
                  borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                }}
              />
            </Card>
          );
        })}
      </div>
    </Stack>
  );
}

import { useEffect, useMemo, useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Box,
  Text,
  Heading,
  Input,
  Select,
  Checkbox,
  RadioGroup,
  Button,
  Divider,
  Badge,
  MotionKeyframes,
  useMotion,
} from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

interface Props {
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];

  /** Action Contract: complete */
  onComplete?: (data: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void | Promise<void>;
}

interface FormData {
  name: string;
  email: string;
  avatar: string;
  role: string;
  emailNotifications: boolean;
  theme: string;
}

export default function GeneratedComponent(props: Props) {
  const { avatarOptions, roleOptions } = props;
  const { motionEnabled } = useMotion();

  const [currentStep, setCurrentStep] = useState(0);
  const [attemptedNext, setAttemptedNext] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const [formData, setFormData] = useState<FormData>({
    name: props.initialProfile?.name ?? '',
    email: props.initialProfile?.email ?? '',
    avatar: props.initialProfile?.avatar ?? '',
    role: props.initialProfile?.role ?? '',
    emailNotifications: props.initialProfile?.emailNotifications ?? false,
    theme:
      props.initialProfile?.theme === 'dark' || props.initialProfile?.theme === 'light'
        ? props.initialProfile.theme
        : 'light',
  });

  useEffect(() => {
    setFormData({
      name: props.initialProfile?.name ?? '',
      email: props.initialProfile?.email ?? '',
      avatar: props.initialProfile?.avatar ?? '',
      role: props.initialProfile?.role ?? '',
      emailNotifications: props.initialProfile?.emailNotifications ?? false,
      theme:
        props.initialProfile?.theme === 'dark' || props.initialProfile?.theme === 'light'
          ? props.initialProfile.theme
          : 'light',
    });
  }, [props.initialProfile]);

  const emailFormatValid = /^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(formData.email.trim());
  const step1Valid =
    formData.name.trim() !== '' && formData.email.trim() !== '' && emailFormatValid && formData.avatar !== '';
  const step2Valid = formData.role.trim() !== '' && (formData.theme === 'light' || formData.theme === 'dark');
  const progressPercent = ((currentStep + 1) / 3) * 100;

  const errors = useMemo(() => {
    const nextErrors: { name?: string; email?: string; avatar?: string; role?: string } = {};
    if (attemptedNext || currentStep > 0) {
      if (formData.name.trim() === '') nextErrors.name = 'Name is required';
      if (formData.email.trim() === '') nextErrors.email = 'Email is required';
      else if (!emailFormatValid) nextErrors.email = 'Invalid email format';
      if (formData.avatar === '') nextErrors.avatar = 'Please select an avatar';
      if (formData.role.trim() === '') nextErrors.role = 'Role is required';
    }
    return nextErrors;
  }, [attemptedNext, currentStep, emailFormatValid, formData]);

  const handleNext = () => {
    setAttemptedNext(true);
    if (currentStep === 0 && step1Valid) {
      setCurrentStep(1);
      setAttemptedNext(false);
    } else if (currentStep === 1 && step2Valid) {
      setCurrentStep(2);
      setAttemptedNext(false);
    }
  };

  const handleBack = () => {
    if (currentStep > 0) setCurrentStep((s) => s - 1);
  };

  const handleComplete = async () => {
    const cb = props.onComplete ?? (() => undefined);
    setIsSubmitting(true);
    try {
      await cb({
        name: formData.name.trim(),
        email: formData.email.trim(),
        avatar: formData.avatar,
        role: formData.role,
        emailNotifications: formData.emailNotifications,
        theme: formData.theme,
      });
    } finally {
      setIsSubmitting(false);
    }
  };

  const canProceed = currentStep === 0 ? step1Valid : currentStep === 1 ? step2Valid : true;

  return (
    <Container maxWidth="md" padding={24} center>
      <MotionKeyframes />
      <Card padding={24} shadow="md" border>
        <Stack gap={20}>
          <Stack gap={8}>
            <Heading level={2}>Onboarding Setup</Heading>
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Complete your profile in three quick steps.
            </Text>
          </Stack>

          <Stack gap={10}>
            <Row justify="between" align="center">
              <Row gap={8} align="center">
                <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                  Step {currentStep + 1} of 3
                </Text>
                <Badge variant="primary" size="sm">
                  {currentStep + 1}/3
                </Badge>
              </Row>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {Math.round(progressPercent)}%
              </Text>
            </Row>
            <Box
              style={{
                height: 10,
                width: '100%',
                background: 'var(--ggui-color-outlineVariant, #e4e4e7)',
                borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                overflow: 'hidden',
              }}
              role="progressbar"
              aria-valuemin={0}
              aria-valuemax={100}
              aria-valuenow={Math.round(progressPercent)}
              aria-label="Onboarding progress"
            >
              <Box
                style={{
                  height: '100%',
                  width: `${progressPercent}%`,
                  background: 'var(--ggui-color-primary-600, #0284c7)',
                  borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                  transition: transition.colors,
                }}
              />
            </Box>
          </Stack>

          <Divider />

          <Box
            style={{
              animation: motionEnabled ? animation.slideInUp : 'none',
              transition: motionEnabled ? transition.normal : 'none',
            }}
          >
            {currentStep === 0 && (
              <Stack gap={16}>
                <Input
                  label="Name"
                  type="text"
                  required
                  value={formData.name}
                  onChange={(value) => setFormData((p) => ({ ...p, name: value }))}
                  error={attemptedNext ? errors.name : undefined}
                />
                <Input
                  label="Email"
                  type="email"
                  required
                  value={formData.email}
                  onChange={(value) => setFormData((p) => ({ ...p, email: value }))}
                  error={attemptedNext ? errors.email : undefined}
                />
                <Stack gap={8}>
                  <Text variant="label">Avatar</Text>
                  {avatarOptions.length === 0 ? (
                    <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      No avatars available.
                    </Text>
                  ) : (
                    <Row wrap gap={8}>
                      {avatarOptions.map((avatar) => {
                        const selected = formData.avatar === avatar;
                        return (
                          <Box
                            key={avatar}
                            style={{
                              border: selected
                                ? '2px solid var(--ggui-color-primary-600, #0284c7)'
                                : '1px solid var(--ggui-color-outline, #d4d4d8)',
                              borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                              background: selected
                                ? 'var(--ggui-color-primary-50, #f0f9ff)'
                                : 'var(--ggui-color-surface, #fafafa)',
                              transition: transition.colors,
                            }}
                          >
                            <Button
                              variant={selected ? 'primary' : 'outline'}
                              size="lg"
                              onClick={() => setFormData((p) => ({ ...p, avatar }))}
                              aria-label={`Select avatar ${avatar}`}
                              aria-pressed={selected}
                            >
                              {avatar}
                            </Button>
                          </Box>
                        );
                      })}
                    </Row>
                  )}
                  {attemptedNext && errors.avatar && (
                    <Text variant="caption" color="var(--ggui-color-error-600, #dc2626)">
                      {errors.avatar}
                    </Text>
                  )}
                </Stack>
              </Stack>
            )}

            {currentStep === 1 && (
              <Stack gap={16}>
                <Select
                  label="Role"
                  required
                  placeholder="Select a role"
                  value={formData.role}
                  onChange={(value) => setFormData((p) => ({ ...p, role: value }))}
                  options={roleOptions.map((role) => ({ value: role, label: role }))}
                  error={attemptedNext ? errors.role : undefined}
                />
                <Checkbox
                  label="Email notifications"
                  checked={formData.emailNotifications}
                  onChange={(checked) => setFormData((p) => ({ ...p, emailNotifications: checked }))}
                />
                <RadioGroup
                  label="Theme"
                  direction="horizontal"
                  value={formData.theme}
                  onChange={(value) => setFormData((p) => ({ ...p, theme: value }))}
                  options={[
                    { value: 'light', label: 'Light' },
                    { value: 'dark', label: 'Dark' },
                  ]}
                />
              </Stack>
            )}

            {currentStep === 2 && (
              <Stack gap={12}>
                <Heading level={3}>Review & Confirm</Heading>
                <Divider />
                <Row justify="between">
                  <Text variant="label">Name</Text>
                  <Text variant="body">{formData.name}</Text>
                </Row>
                <Row justify="between">
                  <Text variant="label">Email</Text>
                  <Text variant="body">{formData.email}</Text>
                </Row>
                <Row justify="between">
                  <Text variant="label">Avatar</Text>
                  <Text variant="body">{formData.avatar}</Text>
                </Row>
                <Row justify="between">
                  <Text variant="label">Role</Text>
                  <Text variant="body">{formData.role}</Text>
                </Row>
                <Row justify="between">
                  <Text variant="label">Email Notifications</Text>
                  <Text variant="body">{formData.emailNotifications ? 'On' : 'Off'}</Text>
                </Row>
                <Row justify="between">
                  <Text variant="label">Theme</Text>
                  <Text variant="body">{formData.theme}</Text>
                </Row>
              </Stack>
            )}
          </Box>

          <Divider />

          <Row justify="between" align="center">
            {currentStep === 0 ? <Box /> : <Button variant="outline" onClick={handleBack}>{currentStep === 2 ? 'Go Back' : 'Back'}</Button>}

            {currentStep < 2 ? (
              <Button variant="primary" onClick={handleNext} disabled={!canProceed}>
                Next
              </Button>
            ) : (
              <Button variant="primary" onClick={handleComplete} loading={isSubmitting} disabled={isSubmitting}>
                Complete Setup
              </Button>
            )}
          </Row>
        </Stack>
      </Card>
      <__GGUI_META__ category="forms" description="A reusable 3-step onboarding wizard with validation, progress indicator, animated transitions, and final completion callback wiring." />
    </Container>
  );
}

import { Card, Stack, Row, Box, Text, Divider } from '@ggui-ai/design/primitives';
import { transition } from '@ggui-ai/design/tokens';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent({
  city = '—',
  temperature = 0,
  condition = 'Unknown',
  humidity = 0,
  windSpeed = 0,
  unit = 'C',
  forecast = [],
}: Props) {
  const normalizedUnit = unit?.toUpperCase() === 'F' ? 'F' : 'C';

  const formatTemp = (value?: number) =>
    typeof value === 'number' ? `${value}°${normalizedUnit}` : `--°${normalizedUnit}`;

  const fallbackIcon = condition?.trim() ? condition.trim().charAt(0).toUpperCase() : '❔';

  return (
    <Card
      padding={24}
      shadow="sm"
      border
      role="region"
      aria-label={`Weather in ${city}`}
      style={{
        background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
        borderColor: 'var(--ggui-color-outlineVariant, #e4e4e7)',
        transition: `${transition.colors}, ${transition.transform}`,
      }}
    >
      <Stack gap={16}>
        <Row justify="between" align="start">
          <Stack gap={4}>
            <Text variant="h3" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
              {city}
            </Text>
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {condition}
            </Text>
          </Stack>

          <Stack align="end" gap={4}>
            <Box aria-label={condition}>
              <Text
                variant="h2"
                color="var(--ggui-color-primary-600, #0284c7)"
                style={{ lineHeight: 1 }}
              >
                {fallbackIcon}
              </Text>
            </Box>
            <Text
              variant="h1"
              color="var(--ggui-color-onSurface, #18181b)"
              style={{ fontSize: 'var(--ggui-font-size-4xl, 36px)' }}
            >
              {temperature}°{normalizedUnit}
            </Text>
          </Stack>
        </Row>

        <Row gap={16} wrap>
          <Box
            style={{
              background: 'var(--ggui-color-surface, #fafafa)',
              border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
              borderRadius: 'var(--ggui-shape-radius-md, 8px)',
              padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)',
              transition: transition.colors,
            }}
          >
            <Stack gap={4}>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Humidity
              </Text>
              <Text variant="body" weight="medium" color="var(--ggui-color-onSurface, #18181b)">
                {humidity}%
              </Text>
            </Stack>
          </Box>

          <Box
            style={{
              background: 'var(--ggui-color-surface, #fafafa)',
              border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
              borderRadius: 'var(--ggui-shape-radius-md, 8px)',
              padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)',
              transition: transition.colors,
            }}
          >
            <Stack gap={4}>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Wind
              </Text>
              <Text variant="body" weight="medium" color="var(--ggui-color-onSurface, #18181b)">
                {windSpeed} km/h
              </Text>
            </Stack>
          </Box>
        </Row>

        <Divider orientation="horizontal" margin={0} />

        <Row
          gap={8}
          justify="between"
          wrap
          aria-label="5-day forecast"
        >
          {forecast.map((item, index) => {
            const day = item.day ?? '—';
            const icon = item.icon ?? '❔';
            const high = formatTemp(item.high);
            const low = formatTemp(item.low);

            return (
              <Box
                key={item.day ?? index}
                role="group"
                aria-label={`${day}: ${high} high, ${low} low`}
                style={{
                  background: 'var(--ggui-color-surface, #fafafa)',
                  border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                  borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                  padding: 'var(--ggui-spacing-2, 8px)',
                  minWidth: 72,
                  flex: 1,
                  transition: `${transition.colors}, ${transition.transform}`,
                }}
              >
                <Stack gap={4} align="center">
                  <Text variant="caption" weight="medium" color="var(--ggui-color-onSurface, #18181b)">
                    {day}
                  </Text>
                  <Text
                    variant="body"
                    color="var(--ggui-color-primary-600, #0284c7)"
                    aria-label={item.day ? `${item.day} condition` : 'Forecast condition'}
                  >
                    {icon}
                  </Text>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {high}/{low}
                  </Text>
                </Stack>
              </Box>
            );
          })}
        </Row>
      </Stack>
    </Card>
  );
}

import { useEffect, useMemo, useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Button,
  Input,
  Select,
  Badge,
  Divider,
  Box,
  Icon,
  Toast,
} from '@ggui-ai/design/primitives';
import { transition } from '@ggui-ai/design/tokens';

interface Props {
  /** Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate */
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>;
  /** Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}] */
  columns: Array<{ id?: string; name?: string }>;
  taskUpdate?: (payload: { action: 'move' | 'edit' | 'create'; taskId: string; data: Record<string, unknown> }) => Promise<void> | void;
}

type Task = { id: string; title: string; priority: 'low' | 'medium' | 'high'; assignee: string; column: string; dueDate?: string };

const defaultColumns: Array<{ id: string; name: string }> = [
  { id: 'todo', name: 'To Do' },
  { id: 'in-progress', name: 'In Progress' },
  { id: 'done', name: 'Done' },
];

const normalizeTask = (task: Props['tasks'][number], index: number, fallbackColumnId: string): Task => ({
  id: task.id || `task-${Date.now()}-${index}`,
  title: task.title || '',
  priority: task.priority || 'low',
  assignee: task.assignee || 'UN',
  column: task.column || fallbackColumnId,
  dueDate: task.dueDate,
});

export default function GeneratedComponent(props: Props) {
  const columns = useMemo(
    () =>
      (props.columns && props.columns.length ? props.columns : defaultColumns).map((c, i) => ({
        id: c.id || `column-${i}`,
        name: c.name || `Column ${i + 1}`,
      })),
    [props.columns]
  );

  const todoColumnId = columns.find((c) => c.id === 'todo')?.id || columns[0]?.id || 'todo';
  const doneColumnId = columns.find((c) => c.id === 'done')?.id || columns.find((c) => (c.name || '').toLowerCase() === 'done')?.id || 'done';

  const [localTasks, setLocalTasks] = useState<Task[]>(
    (props.tasks && props.tasks.length ? props.tasks : []).map((t, i) => normalizeTask(t, i, todoColumnId))
  );
  const [addFormOpenByColumn, setAddFormOpenByColumn] = useState<Record<string, boolean>>({});
  const [newTaskByColumn, setNewTaskByColumn] = useState<Record<string, { title: string; priority: 'low' | 'medium' | 'high' }>>({});
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState('');
  const [moveSelectionByTask, setMoveSelectionByTask] = useState<Record<string, string>>({});
  const [errors, setErrors] = useState<Record<string, string>>({});
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [feedback, setFeedback] = useState<{ visible: boolean; variant: 'success' | 'error' | 'info'; message: string }>({
    visible: false,
    variant: 'info',
    message: '',
  });

  useEffect(() => {
    const incoming = (props.tasks && props.tasks.length ? props.tasks : []).map((t, i) => normalizeTask(t, i, todoColumnId));
    setLocalTasks(incoming);
  }, [props.tasks, todoColumnId]);

  const total = localTasks.length;
  const completed = localTasks.filter((t) => t.column === doneColumnId).length;

  const priorityBadgeVariant = (p: 'low' | 'medium' | 'high') => (p === 'low' ? 'secondary' : p === 'medium' ? 'warning' : 'error');

  const handleCreate = async (columnId: string) => {
    const draft = newTaskByColumn[columnId] || { title: '', priority: 'low' as const };
    const title = draft.title.trim();
    if (!title || title.length < 2) {
      setErrors((prev) => ({ ...prev, [`new-${columnId}`]: 'Title is required and must be at least 2 characters.' }));
      return;
    }
    setErrors((prev) => ({ ...prev, [`new-${columnId}`]: '' }));
    setIsSubmitting(true);
    const taskId = `task-${Date.now()}`;
    const newTask: Task = { id: taskId, title, priority: draft.priority || 'low', assignee: 'UN', column: todoColumnId };
    try {
      setLocalTasks((prev) => [...prev, newTask]);
      if (props.taskUpdate) {
        await props.taskUpdate({ action: 'create', taskId, data: newTask });
      }
      setFeedback({ visible: true, variant: 'success', message: 'Task created successfully.' });
      setAddFormOpenByColumn((prev) => ({ ...prev, [columnId]: false }));
      setNewTaskByColumn((prev) => ({ ...prev, [columnId]: { title: '', priority: 'low' } }));
    } catch {
      setFeedback({ visible: true, variant: 'error', message: 'Failed to create task.' });
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleSaveEdit = async (taskId: string) => {
    const title = editingTitle.trim();
    if (!title) {
      setErrors((prev) => ({ ...prev, [`edit-${taskId}`]: 'Title is required.' }));
      return;
    }
    setErrors((prev) => ({ ...prev, [`edit-${taskId}`]: '' }));
    const previous = localTasks;
    setLocalTasks((prev) => prev.map((t) => (t.id === taskId ? { ...t, title } : t)));
    try {
      if (props.taskUpdate) await props.taskUpdate({ action: 'edit', taskId, data: { title } });
      setFeedback({ visible: true, variant: 'success', message: 'Task updated.' });
      setEditingTaskId(null);
      setEditingTitle('');
    } catch {
      setLocalTasks(previous);
      setFeedback({ visible: true, variant: 'error', message: 'Failed to update task.' });
    }
  };

  const handleMove = async (taskId: string, newColumn: string) => {
    const previous = localTasks;
    setMoveSelectionByTask((prev) => ({ ...prev, [taskId]: newColumn }));
    setLocalTasks((prev) => prev.map((t) => (t.id === taskId ? { ...t, column: newColumn } : t)));
    try {
      if (props.taskUpdate) await props.taskUpdate({ action: 'move', taskId, data: { column: newColumn } });
      setFeedback({ visible: true, variant: 'success', message: 'Task moved.' });
    } catch {
      setLocalTasks(previous);
      setFeedback({ visible: true, variant: 'error', message: 'Failed to move task.' });
    }
  };

  return (
    <Container maxWidth="full" padding={24}>
      <Stack gap={16}>
        <Card shadow="sm" border>
          <Row justify="between" align="center">
            <Text variant="h3" color="var(--ggui-color-onSurface, #18181b)">Task Board Summary</Text>
            <Row gap={16}>
              <Text variant="label" color="var(--ggui-color-primary-600, #0284c7)">Total: {total}</Text>
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Completed: {completed}</Text>
            </Row>
          </Row>
        </Card>

        <Divider />

        <Row gap={16} align="start" wrap>
          {columns.map((column) => {
            const columnTasks = localTasks.filter((t) => t.column === column.id);
            const addDraft = newTaskByColumn[column.id] || { title: '', priority: 'low' as const };

            return (
              <Box
                key={column.id}
                style={{ flex: '1 1 320px', minWidth: '280px' } as React.CSSProperties}
              >
                <Card shadow="sm" border>
                  <Stack gap={12}>
                    <Row justify="between" align="center">
                      <Text variant="h3" color="var(--ggui-color-onSurface, #18181b)">{column.name}</Text>
                      <Text variant="label" color="var(--ggui-color-primary-600, #0284c7)">{columnTasks.length}</Text>
                    </Row>

                    <Stack gap={8} role="region" aria-label={`${column.name} column`} aria-live="polite">
                      {columnTasks.map((task) => (
                        <Card key={task.id} shadow="none" border>
                          <Stack gap={8}>
                            {editingTaskId === task.id ? (
                              <Stack gap={8}>
                                <Input
                                  label="Task title"
                                  value={editingTitle}
                                  onChange={setEditingTitle}
                                  required
                                  error={errors[`edit-${task.id}`] || ''}
                                />
                                <Row gap={8}>
                                  <Button
                                    size="xs"
                                    variant="primary"
                                    onClick={() => handleSaveEdit(task.id)}
                                  >
                                    Save
                                  </Button>
                                  <Button
                                    size="xs"
                                    variant="ghost"
                                    onClick={() => {
                                      setEditingTaskId(null);
                                      setEditingTitle('');
                                    }}
                                  >
                                    Cancel
                                  </Button>
                                </Row>
                              </Stack>
                            ) : (
                              <Row justify="between" align="center">
                                <Text
                                  variant="body"
                                  color="var(--ggui-color-onSurface, #18181b)"
                                  onDoubleClick={() => {
                                    setEditingTaskId(task.id);
                                    setEditingTitle(task.title);
                                  }}
                                >
                                  {task.title}
                                </Text>
                                <Button
                                  size="xs"
                                  variant="ghost"
                                  onClick={() => {
                                    setEditingTaskId(task.id);
                                    setEditingTitle(task.title);
                                  }}
                                >
                                  Edit
                                </Button>
                              </Row>
                            )}

                            <Row gap={8} align="center">
                              <Badge variant={priorityBadgeVariant(task.priority)} size="sm">{task.priority}</Badge>
                              <Row gap={4} align="center" aria-label={`Assignee ${task.assignee || 'UN'}`}>
                                <Icon name="user" size={14} color="var(--ggui-color-onSurfaceVariant, #52525b)" />
                                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{task.assignee || 'UN'}</Text>
                              </Row>
                              {task.dueDate ? (
                                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                                  Due: {task.dueDate}
                                </Text>
                              ) : null}
                            </Row>

                            <Select
                              label="Move to"
                              value={moveSelectionByTask[task.id] || task.column}
                              onChange={(value) => handleMove(task.id, value)}
                              options={columns.map((c) => ({ value: c.id, label: c.name }))}
                            />
                          </Stack>
                        </Card>
                      ))}
                    </Stack>

                    <Button
                      variant="outline"
                      size="sm"
                      leftIcon={<Icon name="plus" size={14} />}
                      onClick={() => setAddFormOpenByColumn((prev) => ({ ...prev, [column.id]: !prev[column.id] }))}
                    >
                      Add Task
                    </Button>

                    {addFormOpenByColumn[column.id] ? (
                      <Card shadow="none" border>
                        <Stack gap={8}>
                          <Input
                            label="Task title"
                            value={addDraft.title}
                            onChange={(value) =>
                              setNewTaskByColumn((prev) => ({
                                ...prev,
                                [column.id]: { ...addDraft, title: value },
                              }))
                            }
                            required
                            error={errors[`new-${column.id}`] || ''}
                          />
                          <Select
                            label="Priority"
                            value={addDraft.priority}
                            onChange={(value) =>
                              setNewTaskByColumn((prev) => ({
                                ...prev,
                                [column.id]: { ...addDraft, priority: (value as 'low' | 'medium' | 'high') || 'low' },
                              }))
                            }
                            options={[
                              { value: 'low', label: 'Low' },
                              { value: 'medium', label: 'Medium' },
                              { value: 'high', label: 'High' },
                            ]}
                          />
                          <Button
                            variant="primary"
                            size="sm"
                            type="submit"
                            loading={isSubmitting}
                            disabled={isSubmitting || addDraft.title.trim().length < 2}
                            onClick={() => handleCreate(column.id)}
                          >
                            Create Task
                          </Button>
                        </Stack>
                      </Card>
                    ) : null}
                  </Stack>
                </Card>
              </Box>
            );
          })}
        </Row>

        <Toast
          visible={feedback.visible}
          variant={feedback.variant}
          title={feedback.variant === 'success' ? 'Success' : feedback.variant === 'error' ? 'Error' : 'Info'}
          message={feedback.message}
          onClose={() => setFeedback((prev) => ({ ...prev, visible: false }))}
        />
      </Stack>
    </Container>
  );
}

