import React, { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Heading,
  MotionKeyframes,
  useMotion
} from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Stock[];
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function StockDashboard({
  stocks: initialStocks = [],
  lastUpdated: initialLastUpdated,
}: Props) {
  const [stocks, setStocks] = useState<Stock[]>(initialStocks);
  const [lastUpdated, setLastUpdated] = useState<string | undefined>(initialLastUpdated);
  const { motionEnabled } = useMotion();

  // Stream Contract: Listen for live data updates from the agent
  useEffect(() => {
    const handleUpdate = (event: Event) => {
      const customEvent = event as CustomEvent;
      const data = customEvent.detail;

      if (data) {
        if (Array.isArray(data.stocks)) {
          setStocks(data.stocks);
        }
        if (data.lastUpdated) {
          setLastUpdated(data.lastUpdated);
        }
      }
    };

    // Use global listener for agent data stream
    addEventListener('ggui:agent-data', handleUpdate);
    return () => removeEventListener('ggui:agent-data', handleUpdate);
  }, []);

  const formatPrice = (price?: number) => {
    if (price === undefined) return '0.00';
    return price.toLocaleString(undefined, {
      minimumFractionDigits: 2,
      maximumFractionDigits: 2,
    });
  };

  const formatPercent = (percent?: number) => {
    if (percent === undefined) return '0.00%';
    return `${percent >= 0 ? '+' : ''}${percent.toFixed(2)}%`;
  };

  const formatTime = (isoString?: string) => {
    if (!isoString) return 'Waiting...';
    try {
      const date = new Date(isoString);
      return date.toLocaleTimeString(undefined, {
        hour: '2-digit',
        minute: '2-digit',
        second: '2-digit',
      });
    } catch {
      return 'Live';
    }
  };

  const renderStockCard = (stock: Stock, index: number) => {
    const isPositive = (stock.change || 0) >= 0;
    const colorVar = isPositive
      ? 'var(--ggui-color-success-600, #16a34a)'
      : 'var(--ggui-color-error-600, #dc2626)';
    const borderColorVar = isPositive
      ? 'var(--ggui-color-success-500, #22c55e)'
      : 'var(--ggui-color-error-500, #ef4444)';

    return (
      <Card
        key={stock.symbol || `stock-${index}`}
        padding="var(--ggui-spacing-5, 20px)"
        shadow="md"
        border
        style={{
          borderColor: borderColorVar,
          animation: motionEnabled ? animation.slideInUp : 'none',
          animationDelay: `${index * 50}ms`,
          borderWidth: '2px',
          flex: '1 1 300px',
          minWidth: '280px',
          transition: 'border-color 200ms ease',
        }}
      >
        <Stack gap={16}>
          <Row justify="between" align="start">
            <Stack gap={2}>
              <Heading level={3}>
                {stock.symbol || '---'}
              </Heading>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {stock.name || 'Company Name'}
              </Text>
            </Stack>
            <Heading level={2}>
              {formatPrice(stock.price)}
            </Heading>
          </Row>

          <Row justify="end" align="center" gap={12}>
            <Text
              weight="bold"
              style={{ color: colorVar, fontSize: 'var(--ggui-font-size-base, 16px)' }}
            >
              {stock.change !== undefined && stock.change > 0 ? '+' : ''}
              {stock.change?.toFixed(2) || '0.00'}
            </Text>
            <Row align="center" gap={4} style={{
              color: 'var(--ggui-color-surface, #ffffff)',
              backgroundColor: colorVar,
              padding: 'var(--ggui-spacing-1, 4px) var(--ggui-spacing-3, 12px)',
              borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
              transition: 'background-color 200ms ease',
            }}>
              <Text weight="bold" style={{ color: 'inherit', fontSize: 'var(--ggui-font-size-xs, 12px)' }}>
                {isPositive ? '▲' : '▼'}
              </Text>
              <Text weight="semibold" style={{ color: 'inherit', fontSize: 'var(--ggui-font-size-sm, 14px)' }}>
                {formatPercent(stock.changePercent)}
              </Text>
            </Row>
          </Row>
        </Stack>
      </Card>
    );
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <MotionKeyframes />
      <Stack gap={32}>
        {/* Header Section */}
        <Row justify="between" align="end" wrap gap={16}>
          <Stack gap={4}>
            <Heading level={1}>Market Watch</Heading>
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Live price feeds from global exchanges
            </Text>
          </Stack>
          <Stack align="end" gap={4}>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)" style={{ textTransform: 'uppercase', letterSpacing: '0.05em' }}>
              Last Updated
            </Text>
            <Heading level={4}>
              {formatTime(lastUpdated)}
            </Heading>
          </Stack>
        </Row>

        {/* Dashboard Content */}
        {!stocks || stocks.length === 0 ? (
          <Card padding="var(--ggui-spacing-12, 48px)" style={{ borderStyle: 'dashed' }}>
            <Stack align="center" gap={16}>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Syncing with market data stream...
              </Text>
              <div style={{
                width: 32,
                height: 32,
                border: '3px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                borderTopColor: 'var(--ggui-color-primary-600, #0284c7)',
                borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                animation: 'ggui-spin 1s linear infinite'
              }} />
              <style>{`
                @keyframes ggui-spin { 
                  from { transform: rotate(0deg); }
                  to { transform: rotate(360deg); } 
                }
              `}</style>
            </Stack>
          </Card>
        ) : (
          <Row wrap gap={24} style={{ display: 'flex' }}>
             {stocks.map((stock, i) => renderStockCard(stock, i))}
          </Row>
        )}

        {/* Informational Footer */}
        <Row justify="center" style={{ marginTop: 'var(--ggui-spacing-4, 16px)' }}>
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">
            Trading involves risk. Data streams are automated and verified for accuracy.
          </Text>
        </Row>
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Heading,
  Input,
  Select,
  Checkbox,
  Button,
  Divider,
  Icon,
  Box,
  Spacer,
  MotionKeyframes,
  useMotion
} from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

interface Props {
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string };
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Action handler when onboarding is complete */
  onComplete: (data: any) => void;
}

/**
 * A 3-step onboarding wizard for user profile setup and preferences.
 */
export default function OnboardingWizard(props: Props) {
  const { initialProfile, avatarOptions, roleOptions, onComplete } = props;
  const { motionEnabled } = useMotion();
  const [step, setStep] = useState(0);

  // State for form data
  const [formData, setFormData] = useState({
    name: initialProfile?.name || '',
    email: initialProfile?.email || '',
    avatar: initialProfile?.avatar || (avatarOptions && avatarOptions.length > 0 ? avatarOptions[0] : ''),
    role: initialProfile?.role || (roleOptions && roleOptions.length > 0 ? roleOptions[0] : ''),
    emailNotifications: initialProfile?.emailNotifications ?? true,
    theme: initialProfile?.theme || 'light',
  });

  // State for validation errors
  const [errors, setErrors] = useState<Record<string, string>>({});

  // Validation logic
  const validateEmail = (email: string) => {
    if (!email) return 'Email is required';
    if (!/^[^@]+@[^@]+\.[^@]+$/.test(email)) return 'Invalid email format';
    return '';
  };

  const updateField = (field: string, value: any) => {
    setFormData(prev => ({ ...prev, [field]: value }));
    if (field === 'email') setErrors(prev => ({ ...prev, email: validateEmail(value) }));
    if (field === 'name') setErrors(prev => ({ ...prev, name: value ? '' : 'Name is required' }));
  };

  const isStep1Valid = !!formData.name && !!formData.email && !errors.email && !errors.name;

  const handleNext = () => {
    if (step === 0 && !isStep1Valid) {
      setErrors({
        name: formData.name ? '' : 'Name is required',
        email: validateEmail(formData.email)
      });
      return;
    }
    setStep(s => Math.min(s + 1, 2));
  };

  const handleBack = () => setStep(s => Math.max(s - 1, 0));

  const handleComplete = () => {
    if (onComplete) onComplete(formData);
  };

  const progress = ((step + 1) / 3) * 100;

  return (
    <Container maxWidth="md">
      <MotionKeyframes />
      <Stack gap={24}>
        {/* Step Indicator & Progress Bar */}
        <Card padding={24} border shadow="sm">
          <Stack gap={12}>
            <Row justify="between" align="center">
              <Text variant="label" weight="semibold">Step {step + 1} of 3</Text>
              <Text variant="caption" color="var(--ggui-color-primary-600)" weight="bold">
                {step === 0 ? 'PROFILE SETUP' : step === 1 ? 'PREFERENCES' : 'REVIEW & CONFIRM'}
              </Text>
            </Row>
            <div style={{ 
              height: 8, 
              background: 'var(--ggui-color-outlineVariant)', 
              borderRadius: 4, 
              overflow: 'hidden' 
            }}>
              <div style={{ 
                height: '100%', 
                width: `${progress}%`, 
                background: 'var(--ggui-color-primary-600)', 
                transition: transition.normal,
                borderRadius: 4
              }} />
            </div>
          </Stack>
        </Card>

        {/* Form Container */}
        <Card padding={32} style={{ 
          animation: motionEnabled ? animation.fadeIn : 'none',
          minHeight: 450,
          display: 'flex',
          flexDirection: 'column'
        }} key={step}>
          <div style={{ flex: 1 }}>
            {step === 0 && (
              <Stack gap={24}>
                <Heading level={2}>Profile Setup</Heading>
                <Input
                  label="Name"
                  placeholder="Enter your full name"
                  value={formData.name}
                  onChange={(v) => updateField('name', v)}
                  error={errors.name}
                  required
                />
                <Input
                  label="Email"
                  type="email"
                  placeholder="name@example.com"
                  value={formData.email}
                  onChange={(v) => updateField('email', v)}
                  error={errors.email}
                  required
                />
                <Stack gap={12}>
                  <Text variant="label" weight="medium">Choose your avatar</Text>
                  <Row gap={12} wrap>
                    {avatarOptions && avatarOptions.map(emoji => (
                      <button
                        key={emoji}
                        onClick={() => updateField('avatar', emoji)}
                        style={{
                          width: 64,
                          height: 64,
                          fontSize: 28,
                          borderRadius: 'var(--ggui-shape-radius-lg)',
                          border: formData.avatar === emoji 
                            ? '2px solid var(--ggui-color-primary-600)' 
                            : '1px solid var(--ggui-color-outline)',
                          background: formData.avatar === emoji 
                            ? 'var(--ggui-color-primary-50)' 
                            : 'var(--ggui-color-surface)',
                          cursor: 'pointer',
                          transition: transition.fast,
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'center'
                        }}
                      >
                        {emoji}
                      </button>
                    ))}
                  </Row>
                </Stack>
              </Stack>
            )}

            {step === 1 && (
              <Stack gap={24}>
                <Heading level={2}>Preferences</Heading>
                <Select
                  label="Role"
                  placeholder="What is your role?"
                  value={formData.role}
                  onChange={(v) => updateField('role', v)}
                  options={roleOptions ? roleOptions.map(r => ({ value: r, label: r })) : []}
                />
                <Divider />
                <Checkbox
                  label="Email Notifications"
                  description="Receive updates and alerts in your inbox"
                  checked={formData.emailNotifications}
                  onChange={(v) => updateField('emailNotifications', v)}
                />
                <Stack gap={12}>
                  <Text variant="label" weight="medium">Theme preference</Text>
                  <Row gap={12}>
                    <Button 
                      variant={formData.theme === 'light' ? 'primary' : 'outline'} 
                      onClick={() => updateField('theme', 'light')}
                      fullWidth
                    >
                      Light Mode
                    </Button>
                    <Button 
                      variant={formData.theme === 'dark' ? 'primary' : 'outline'} 
                      onClick={() => updateField('theme', 'dark')}
                      fullWidth
                    >
                      Dark Mode
                    </Button>
                  </Row>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap={24}>
                <Heading level={2}>Review & Confirm</Heading>
                <Box padding={24} background="var(--ggui-color-surfaceVariant)" borderRadius={16}>
                  <Stack gap={24}>
                    <Row align="center" gap={20}>
                      <div style={{ 
                        fontSize: 48, 
                        width: 80, 
                        height: 80, 
                        background: 'var(--ggui-color-surface)', 
                        borderRadius: 40, 
                        display: 'flex', 
                        alignItems: 'center', 
                        justifyContent: 'center', 
                        border: '2px solid var(--ggui-color-outline)' 
                      }}>
                        {formData.avatar}
                      </div>
                      <Stack gap={4}>
                        <Heading level={3}>{formData.name}</Heading>
                        <Text color="var(--ggui-color-onSurfaceVariant)">{formData.email}</Text>
                      </Stack>
                    </Row>

                    <Divider />

                    <Row justify="between" wrap gap={16}>
                      <Stack gap={4}>
                        <Text variant="caption" weight="bold" color="var(--ggui-color-onSurfaceVariant)">ROLE</Text>
                        <Text weight="medium">{formData.role}</Text>
                      </Stack>
                      <Stack gap={4} align="end">
                        <Text variant="caption" weight="bold" color="var(--ggui-color-onSurfaceVariant)">NOTIFICATIONS</Text>
                        <Text weight="medium">{formData.emailNotifications ? 'Enabled' : 'Disabled'}</Text>
                      </Stack>
                    </Row>

                    <Row justify="between">
                      <Stack gap={4}>
                        <Text variant="caption" weight="bold" color="var(--ggui-color-onSurfaceVariant)">THEME</Text>
                        <Text weight="medium">{formData.theme.toUpperCase()}</Text>
                      </Stack>
                    </Row>
                  </Stack>
                </Box>
              </Stack>
            )}
          </div>

          <Spacer size="flex" />
          <Divider margin={24} />

          {/* Navigation Controls */}
          <Row justify="between">
            {step > 0 ? (
              <Button 
                variant="outline" 
                onClick={handleBack}
                leftIcon={<Icon name="chevron-left" size={18} />}
              >
                Go Back
              </Button>
            ) : (
              <div />
            )}

            {step < 2 ? (
              <Button 
                variant="primary" 
                onClick={handleNext} 
                disabled={step === 0 && !isStep1Valid}
                rightIcon={<Icon name="chevron-right" size={18} />}
              >
                Next Step
              </Button>
            ) : (
              <Button 
                variant="primary" 
                onClick={handleComplete}
                leftIcon={<Icon name="check" size={18} />}
              >
                Complete Setup
              </Button>
            )}
          </Row>
        </Card>
      </Stack>
    </Container>
  );
}

