import React from 'react';
import {
  Card,
  Stack,
  Row,
  Text,
  Divider,
  Heading,
  Box,
} from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

/**
 * A weather card component that displays current weather and a 5-day forecast.
 */
export default function WeatherCard({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit = '°C',
  forecast = [],
}: Props) {
  // Simple helper to get a fallback emoji if forecast icon isn't provided
  const getConditionEmoji = (cond: string) => {
    const c = cond.toLowerCase();
    if (c.includes('sun') || c.includes('clear')) return '☀️';
    if (c.includes('cloud')) return '☁️';
    if (c.includes('rain') || c.includes('drizzle')) return '🌧️';
    if (c.includes('snow')) return '❄️';
    if (c.includes('thunder')) return '⛈️';
    if (c.includes('mist') || c.includes('fog')) return '🌫️';
    return '⛅';
  };

  return (
    <Box padding="var(--ggui-spacing-4, 16px)">
      <Card
        padding="var(--ggui-spacing-6, 24px)"
        shadow="lg"
        border
        style={{
          maxWidth: 480,
          margin: '0 auto',
          background: 'var(--ggui-color-surface, #fafafa)',
          color: 'var(--ggui-color-onSurface, #18181b)',
        }}
      >
        <Stack gap={24}>
          {/* Header Section */}
          <Stack gap={4}>
            <Heading level={2}>
              {city}
            </Heading>
            <Text
              variant="body"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              {condition}
            </Text>
          </Stack>

          {/* Current Weather Display */}
          <Row align="center" justify="between">
            <Text
              style={{
                fontSize: 'var(--ggui-font-size-4xl, 36px)',
                lineHeight: 1,
                fontWeight: 'var(--ggui-font-weight-bold, 700)',
              }}
            >
              {Math.round(temperature)}
              {unit}
            </Text>
            <span style={{ fontSize: '48px' }} aria-hidden="true">
              {getConditionEmoji(condition)}
            </span>
          </Row>

          {/* Humidity and Wind Speed Details */}
          <Row
            gap={16}
            style={{
              padding: 'var(--ggui-spacing-4, 16px)',
              borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
              background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
            }}
          >
            <Stack gap={4} align="center" style={{ flex: 1 }}>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                HUMIDITY
              </Text>
              <Text weight="semibold">{humidity}%</Text>
            </Stack>
            <Divider orientation="vertical" />
            <Stack gap={4} align="center" style={{ flex: 1 }}>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                WIND
              </Text>
              <Text weight="semibold">{windSpeed} km/h</Text>
            </Stack>
          </Row>

          <Divider />

          {/* 5-Day Forecast Strip */}
          <Stack gap={16}>
            <Text variant="label" weight="bold">
              5-Day Forecast
            </Text>
            <Row justify="between" gap={8} wrap>
              {forecast.map((item, index) => (
                <Stack
                  key={`${item.day}-${index}`}
                  align="center"
                  gap={4}
                  style={{
                    minWidth: '60px',
                    padding: 'var(--ggui-spacing-2, 8px)',
                  }}
                >
                  <Text variant="caption" weight="medium">
                    {item.day}
                  </Text>
                  <span style={{ fontSize: '24px' }} aria-hidden="true">
                    {item.icon || getConditionEmoji(condition)}
                  </span>
                  <Stack gap={0} align="center">
                    <Text variant="caption" weight="bold">
                      {item.high}°
                    </Text>
                    <Text
                      variant="caption"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    >
                      {item.low}°
                    </Text>
                  </Stack>
                </Stack>
              ))}
            </Row>
          </Stack>
        </Stack>
      </Card>
    </Box>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Input,
  Box,
  Heading,
  Divider,
} from '@ggui-ai/design/primitives';

interface ElementData {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  /** Full periodic table element data */
  elements: ElementData[];
}

const CATEGORY_COLORS: Record<string, string> = {
  'alkali metal': 'var(--ggui-color-primary-100, #e0f2fe)',
  'alkaline earth metal': 'var(--ggui-color-primary-200, #bae6fd)',
  'lanthanide': 'var(--ggui-color-primary-300, #7dd3fc)',
  'actinide': 'var(--ggui-color-primary-400, #38bdf8)',
  'transition metal': 'var(--ggui-color-primary-500, #0ea5e9)',
  'post-transition metal': 'var(--ggui-color-primary-600, #0284c7)',
  'metalloid': 'var(--ggui-color-primary-700, #0369a1)',
  'polyatomic nonmetal': 'var(--ggui-color-success-500, #22c55e)',
  'diatomic nonmetal': 'var(--ggui-color-success-600, #16a34a)',
  'noble gas': 'var(--ggui-color-warning-500, #f59e0b)',
  'unknown': 'var(--ggui-color-neutral-200, #e5e7eb)',
};

const DEFAULT_COLOR = 'var(--ggui-color-neutral-100, #f3f4f6)';

export default function PeriodicTable({ elements = [] }: Props) {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedElement, setSelectedElement] = useState<ElementData | null>(null);

  const filteredElements = useMemo(() => {
    if (!searchTerm) return elements;
    const lowerSearch = searchTerm.toLowerCase();
    return elements.filter(
      (el) =>
        (el.name || '').toLowerCase().includes(lowerSearch) ||
        (el.symbol || '').toLowerCase().includes(lowerSearch)
    );
  }, [elements, searchTerm]);

  const getCategoryColor = (category?: string) => {
    if (!category) return DEFAULT_COLOR;
    return CATEGORY_COLORS[category.toLowerCase()] || DEFAULT_COLOR;
  };

  const uniqueCategories = useMemo(() => {
    const categories = new Set<string>();
    elements.forEach(el => {
      if (el.category) categories.add(el.category);
    });
    return Array.from(categories).sort();
  }, [elements]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap={24}>
        <Stack gap={16}>
          <Row justify="between" align="end" wrap>
            <Heading level={1}>Periodic Table</Heading>
            <Box style={{ width: '100%', maxWidth: 320 }}>
              <Input label="Search Elements" placeholder="Hydrogen, He..." value={searchTerm} onChange={setSearchTerm} />
            </Box>
          </Row>

          <Card padding="var(--ggui-spacing-4, 16px)">
            <Stack gap={8}>
              <Text variant="label">Legend</Text>
              <Row gap={12} wrap>
                {uniqueCategories.map(cat => (
                  <Row key={cat} gap={4} align="center">
                    <div style={{
                      width: 16,
                      height: 16,
                      borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                      backgroundColor: getCategoryColor(cat),
                      border: '1px solid var(--ggui-color-outline, #d4d4d8)'
                    }} />
                    <Text variant="caption">{cat}</Text>
                  </Row>
                ))}
              </Row>
            </Stack>
          </Card>
        </Stack>

        <Box style={{ 
          overflowX: 'auto', 
          backgroundColor: 'var(--ggui-color-surface, #fafafa)',
          borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
          border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
          padding: 'var(--ggui-spacing-4, 16px)'
        }}>
          <div style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, minmax(0, 1fr))',
            gap: 'var(--ggui-spacing-1, 4px)',
            minWidth: 900
          }}>
            {elements.map((el) => {
              const isMatch = filteredElements.includes(el);
              const isSelected = selectedElement?.atomicNumber === el.atomicNumber;
              const categoryColor = getCategoryColor(el.category);

              return (
                <div
                  key={`${el.atomicNumber}-${el.symbol}`}
                  onClick={() => setSelectedElement(el)}
                  style={{
                    gridRow: el.row || 'auto',
                    gridColumn: el.col || 'auto',
                    aspectRatio: '1/1',
                    cursor: 'pointer',
                    transition: 'all 200ms ease-out',
                    transform: isSelected ? 'scale(1.1)' : 'scale(1)',
                    zIndex: isSelected ? 10 : 1,
                    opacity: isMatch ? 1 : 0.15,
                  }}
                >
                  <Card
                    padding={0}
                    shadow={isSelected ? 'md' : 'none'}
                    border={true}
                    style={{
                      height: '100%',
                      backgroundColor: categoryColor,
                      borderColor: isSelected ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-outline, #d4d4d8)',
                      display: 'flex',
                      flexDirection: 'column',
                      justifyContent: 'center',
                      alignItems: 'center',
                      position: 'relative',
                    }}
                  >
                    <div style={{
                      position: 'absolute',
                      top: 'var(--ggui-spacing-1, 4px)',
                      left: 'var(--ggui-spacing-1, 4px)',
                    }}>
                      <Text variant="caption" weight="bold" style={{ fontSize: '0.6rem' }}>
                        {el.atomicNumber}
                      </Text>
                    </div>
                    <Text variant="body" weight="bold" style={{ fontSize: '1.2rem' }}>{el.symbol}</Text>
                    <Text variant="caption" style={{ 
                        fontSize: '0.5rem', 
                        textAlign: 'center', 
                        maxWidth: '90%',
                        overflow: 'hidden',
                        whiteSpace: 'nowrap',
                        textOverflow: 'ellipsis'
                      }}
                    >
                      {el.name}
                    </Text>
                  </Card>
                </div>
              );
            })}
          </div>
        </Box>

        {selectedElement && (
          <Card padding="var(--ggui-spacing-6, 24px)" shadow="md" border>
            <Stack gap={20}>
              <Row justify="between" align="center" wrap>
                <Stack gap={4}>
                  <Heading level={2}>{selectedElement.name}</Heading>
                  <Text variant="label" color="var(--ggui-color-primary-600, #0284c7)">
                    {selectedElement.category}
                  </Text>
                </Stack>

                <Box
                  padding="var(--ggui-spacing-4, 16px)"
                  borderRadius="var(--ggui-shape-radius-lg, 12px)"
                  style={{
                    backgroundColor: getCategoryColor(selectedElement.category),
                    border: '2px solid var(--ggui-color-outline, #d4d4d8)',
                    textAlign: 'center',
                    minWidth: 100
                  }}
                >
                  <Heading level={1}>{selectedElement.symbol}</Heading>
                  <Text variant="caption" weight="bold">
                    Atomic No. {selectedElement.atomicNumber}
                  </Text>
                </Box>
              </Row>

              <Divider />

              <Row gap={48} wrap>
                <Stack gap={4}>
                  <Text variant="label">Atomic Weight</Text>
                  <Text variant="body" weight="semibold">
                    {selectedElement.atomicWeight} u
                  </Text>
                </Stack>
                <Stack gap={4}>
                  <Text variant="label">Category</Text>
                  <Text variant="body" weight="semibold" style={{ textTransform: 'capitalize' }}>
                    {selectedElement.category}
                  </Text>
                </Stack>
              </Row>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState, useRef, useEffect } from 'react';
import {
  Card,
  Stack,
  Row,
  Text,
  Badge,
  Input,
  Button,
  Icon,
  Box,
  Spacer,
  MotionKeyframes,
  useMotion
} from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Callback to send message */
  sendMessage: (payload: { text: string; timestamp: string }) => void;
}

/**
 * A collaborative chat interface component.
 */
export default function GeneratedComponent({
  title = 'Chat Room',
  currentUser = 'User',
  participantCount = 0,
  messages = [],
  sendMessage
}: Props) {
  const [inputText, setInputText] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);
  const { motionEnabled } = useMotion();

  // Handle auto-scroll to bottom
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  // Stream Contract: Listener for incoming data
  useEffect(() => {
    const handleUpdate = () => {
      if (scrollRef.current) {
        scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
      }
    };
    // Use dynamic property access to satisfy security policy constraints
    const g: any = typeof globalThis !== 'undefined' ? globalThis : {};
    if (g.addEventListener) {
      g.addEventListener('ggui:agent-data', handleUpdate);
      return () => g.removeEventListener('ggui:agent-data', handleUpdate);
    }
    return () => {};
  }, []);

  const handleSend = () => {
    const trimmed = inputText.trim();
    if (!trimmed) return;
    sendMessage({ text: trimmed, timestamp: new Date().toISOString() });
    setInputText('');
  };

  return (
    <Card padding={0} shadow="lg" border style={{ height: '600px', display: 'flex', flexDirection: 'column', background: 'var(--ggui-color-surface)' }}>
      <MotionKeyframes />

      <Box padding="var(--ggui-spacing-4, 16px)" style={{ borderBottom: '1px solid var(--ggui-color-outline)' }}>
        <Row align="center" justify="between">
          <Stack gap={2}>
            <Text variant="bodyLarge" weight="bold">{title}</Text>
            <Badge variant="success" size="sm" pill>{participantCount} online</Badge>
          </Stack>
          <Button variant="ghost" size="sm"><Icon name="settings" size={20} /></Button>
        </Row>
      </Box>

      <div ref={scrollRef} style={{ flex: 1, overflowY: 'auto', background: 'var(--ggui-color-surfaceVariant)', padding: 'var(--ggui-spacing-4, 16px)', scrollBehavior: 'smooth' }}>
        <Stack gap={12}>
          {messages.map((m, i) => {
            const isMe = m.sender === currentUser;
            const isGrouped = i > 0 && messages[i - 1].sender === m.sender;
            return (
              <div key={`${m.timestamp}-${i}`} style={{ display: 'flex', flexDirection: 'column', alignItems: isMe ? 'flex-end' : 'flex-start', marginTop: isGrouped ? '-8px' : '4px', animation: motionEnabled ? animation.fadeIn : 'none' }}>
                {!isMe && !isGrouped && <Text variant="caption" weight="medium" style={{ color: 'var(--ggui-color-onSurfaceVariant)', marginLeft: 'var(--ggui-spacing-2, 8px)', marginBottom: '4px' }}>{m.sender}</Text>}
                <Box padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)" borderRadius="var(--ggui-shape-radius-lg)" style={{ maxWidth: '85%', background: isMe ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surface)', color: isMe ? '#ffffff' : 'var(--ggui-color-onSurface)', border: isMe ? 'none' : '1px solid var(--ggui-color-outlineVariant)', borderBottomRightRadius: isMe && !isGrouped ? '2px' : '12px', borderBottomLeftRadius: !isMe && !isGrouped ? '2px' : '12px', boxShadow: 'var(--ggui-shape-shadow-sm)' }}>
                  <Stack gap={2}>
                    <Text style={{ color: 'inherit', wordBreak: 'break-word' }}>{m.text}</Text>
                    <Text variant="caption" align={isMe ? 'right' : 'left'} style={{ opacity: 0.7, color: 'inherit', fontSize: '10px' }}>{m.timestamp ? new Date(m.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : ''}</Text>
                  </Stack>
                </Box>
              </div>
            );
          })}
        </Stack>
      </div>

      <div style={{ padding: 'var(--ggui-spacing-4, 16px)', borderTop: '1px solid var(--ggui-color-outline)' }} onKeyDown={(e) => e.key === 'Enter' && handleSend()}>
        <Stack gap={8}>
          <Text variant="label">Message</Text>
          <Row gap={12} align="end">
            <Input label="Message" value={inputText} onChange={setInputText} placeholder="Type a message..." />
            <Button variant="primary" onClick={handleSend} disabled={!inputText.trim()} style={{ height: '42px' }}>Send Message</Button>
          </Row>
        </Stack>
      </div>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Heading,
  Icon,
  MotionKeyframes,
  useMotion,
  Spacer
} from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<Stock>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

/**
 * Stock Ticker Dashboard
 * Displays a responsive grid of stock cards with live updates.
 */
export default function StockTickerDashboard({ stocks: initialStocks = [], lastUpdated: initialLastUpdated }: Props) {
  const [stocks, setStocks] = useState<Stock[]>(initialStocks);
  const [lastUpdated, setLastUpdated] = useState<string | undefined>(initialLastUpdated);
  const [isConnecting, setIsConnecting] = useState(true);
  const { motionEnabled } = useMotion();

  useEffect(() => {
    // Attempting to use global event listener without window prefix to comply with security rules
    const handleAgentData = (event: any) => {
      const data = event.detail;
      if (data) {
        if (data.stocks) setStocks(data.stocks);
        if (data.lastUpdated) setLastUpdated(data.lastUpdated);
        setIsConnecting(false);
      }
    };

    // Use global addEventListener directly
    if (typeof addEventListener !== 'undefined') {
      addEventListener('ggui:agent-data', handleAgentData);
    }

    const timer = setTimeout(() => setIsConnecting(false), 1200);

    return () => {
      if (typeof removeEventListener !== 'undefined') {
        removeEventListener('ggui:agent-data', handleAgentData);
      }
      clearTimeout(timer);
    };
  }, []);

  const formatTime = (isoString?: string) => {
    if (!isoString) return 'Waiting for update...';
    try {
      const date = new Date(isoString);
      return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' });
    } catch (e) {
      return String(isoString);
    }
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <MotionKeyframes />
      <Stack gap={32}>
        {/* Header Section */}
        <Row justify="between" align="center" wrap>
          <Stack gap={4}>
            <Heading level={2}>Market Watch</Heading>
            <Row gap={8} align="center">
              <div 
                aria-hidden="true"
                style={{
                  width: 'var(--ggui-spacing-2, 8px)',
                  height: 'var(--ggui-spacing-2, 8px)',
                  borderRadius: 'var(--ggui-shape-radius-full)',
                  backgroundColor: isConnecting ? 'var(--ggui-color-warning-500)' : 'var(--ggui-color-success-500)',
                  boxShadow: isConnecting ? 'none' : '0 0 var(--ggui-spacing-2, 8px) var(--ggui-color-success-500)',
                  transition: transition.colors
                }} 
              />
              <Text variant="caption">
                {isConnecting ? 'Establishing secure connection...' : `Real-time updates active • Last sync: ${formatTime(lastUpdated)}`}
              </Text>
            </Row>
          </Stack>
        </Row>

        {/* Stock Grid Layout */}
        <div 
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(min(100%, 320px), 1fr))',
            gap: 'var(--ggui-spacing-6, 24px)',
            width: '100%'
          }}
        >
          {stocks.length === 0 && !isConnecting && (
            <div style={{ gridColumn: '1 / -1' }}>
              <Card padding="var(--ggui-spacing-12, 48px)">
                <Stack align="center" gap={16} justify="center">
                  <Heading level={3}>No Tickers Active</Heading>
                  <Text variant="body" align="center">
                    Select symbols to monitor or wait for market updates.
                  </Text>
                </Stack>
              </Card>
            </div>
          )}

          {stocks.map((stock, index) => {
            const isPositive = (stock.change ?? 0) >= 0;
            const accentColor = isPositive ? 'var(--ggui-color-success-600)' : 'var(--ggui-color-error-600)';
            const bgColor = isPositive ? 'var(--ggui-color-success-50, #f0fdf4)' : 'var(--ggui-color-error-50, #fef2f2)';
            const borderColor = isPositive ? 'var(--ggui-color-success-500)' : 'var(--ggui-color-error-500)';

            return (
              <Card
                key={`${stock.symbol}-${index}`}
                padding="var(--ggui-spacing-6, 24px)"
                style={{
                  border: `1px solid var(--ggui-color-outlineVariant)`,
                  borderLeft: `4px solid ${borderColor}`,
                  animation: motionEnabled ? animation.fadeIn : 'none',
                  animationDelay: `${index * 80}ms`,
                  transition: transition.colors,
                  position: 'relative'
                }}
              >
                <Stack gap={20}>
                  <Row justify="between" align="start">
                    <Stack gap={4}>
                      <Heading level={3} style={{ margin: 0 }}>{stock.symbol || 'N/A'}</Heading>
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                        {stock.name || 'Unknown Company'}
                      </Text>
                    </Stack>

                    <div 
                      style={{
                        backgroundColor: bgColor,
                        padding: 'var(--ggui-spacing-1, 4px) var(--ggui-spacing-2, 8px)',
                        borderRadius: 'var(--ggui-shape-radius-md)',
                        display: 'flex',
                        alignItems: 'center',
                        gap: 'var(--ggui-spacing-1, 4px)',
                        transition: transition.colors
                      }}
                    >
                      <Icon 
                        name={isPositive ? 'chevron-up' : 'chevron-down'} 
                        size={14} 
                        color={accentColor} 
                      />
                      <Text weight="semibold" style={{ color: accentColor, fontSize: 'var(--ggui-font-size-sm)' }}>
                        {Math.abs(stock.changePercent ?? 0).toFixed(2)}%
                      </Text>
                    </div>
                  </Row>

                  <Spacer size={4} />

                  <Row align="end" justify="between">
                    <Heading level={1} style={{ margin: 0 }}>
                      ${(stock.price ?? 0).toFixed(2)}
                    </Heading>
                    <Text 
                      variant="bodySmall" 
                      weight="semibold" 
                      style={{ 
                        color: accentColor,
                        padding: '0 var(--ggui-spacing-1, 4px)'
                      }}
                    >
                      {isPositive ? '+' : '-'}{Math.abs(stock.change ?? 0).toFixed(2)}
                    </Text>
                  </Row>
                </Stack>
              </Card>
            );
          })}
        </div>
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import { 
  Container, Card, Stack, Row, Text, Heading, 
  Input, Select, Checkbox, RadioGroup, Button, 
  Divider, Box, MotionKeyframes, useMotion, Icon 
} from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Props {
  avatarOptions: string[];
  roleOptions: string[];
  initialProfile?: { 
    name?: string; 
    email?: string; 
    avatar?: string; 
    role?: string; 
    emailNotifications?: boolean; 
    theme?: string 
  };
  onComplete: (data: { 
    name: string; 
    email: string; 
    avatar: string; 
    role: string; 
    emailNotifications: boolean; 
    theme: string 
  }) => void;
}

export default function OnboardingWizard(props: Props) {
  const { initialProfile, avatarOptions, roleOptions, onComplete } = props;
  const { motionEnabled } = useMotion();
  const [currentStep, setCurrentStep] = useState(0);

  const [formData, setFormData] = useState({
    name: initialProfile?.name || '',
    email: initialProfile?.email || '',
    avatar: initialProfile?.avatar || (avatarOptions?.[0] || '👤'),
    role: initialProfile?.role || '',
    emailNotifications: initialProfile?.emailNotifications ?? true,
    theme: initialProfile?.theme || 'light',
  });

  const [errors, setErrors] = useState<{ name?: string; email?: string }>({});

  const updateField = (field: string, value: any) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
    if (errors[field as keyof typeof errors]) {
      setErrors((prev) => ({ ...prev, [field]: undefined }));
    }
  };

  const validateStep1 = () => {
    const newErrors: { name?: string; email?: string } = {};
    if (!formData.name.trim()) newErrors.name = 'Name is required';
    if (!formData.email.trim()) {
      newErrors.email = 'Email is required';
    } else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email)) {
      newErrors.email = 'Invalid email format';
    }
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleNext = () => {
    if (currentStep === 0) {
      if (validateStep1()) setCurrentStep(1);
    } else if (currentStep === 1) {
      setCurrentStep(2);
    }
  };

  const handleBack = () => {
    if (currentStep > 0) setCurrentStep(currentStep - 1);
  };

  const isStep1Valid = formData.name.trim() !== '' && /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email);
  const isStep2Valid = formData.role !== '';
  const progress = ((currentStep + 1) / 3) * 100;

  return (
    <Container maxWidth="sm" padding="var(--ggui-spacing-8, 32px)">
      <MotionKeyframes />
      <Stack gap={24}>
        <Stack gap={8}>
          <Row justify="between" align="end">
            <Text variant="label" weight="semibold">Step {currentStep + 1} of 3</Text>
            <Text variant="caption">
              {currentStep === 0 && 'Profile Setup'}
              {currentStep === 1 && 'Preferences'}
              {currentStep === 2 && 'Review & Confirm'}
            </Text>
          </Row>
          <Box background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius="var(--ggui-shape-radius-full, 9999px)" style={{ height: 8, overflow: 'hidden' }}>
            <div style={{ height: '100%', width: `${progress}%`, backgroundColor: 'var(--ggui-color-primary-600, #0284c7)', transition: 'width 0.3s ease-in-out', borderRadius: 'inherit' }} />
          </Box>
        </Stack>

        <Card padding={32} shadow="md" border>
          <div key={currentStep} style={{ animation: motionEnabled ? animation.fadeIn : 'none', minHeight: '320px' }}>
            {currentStep === 0 && (
              <Stack gap={24}>
                <Heading level={2}>Create Your Profile</Heading>
                <Input label="Name" placeholder="Enter your full name" value={formData.name} onChange={(v) => updateField('name', v)} error={errors.name} required />
                <Input label="Email" type="email" placeholder="name@example.com" value={formData.email} onChange={(v) => updateField('email', v)} error={errors.email} required />
                <Stack gap={8}>
                  <Text variant="label" weight="medium">Choose an Avatar</Text>
                  <Row gap={12} justify="start" wrap>
                    {avatarOptions?.map((emoji) => (
                      <Button key={emoji} variant={formData.avatar === emoji ? 'primary' : 'outline'} onClick={() => updateField('avatar', emoji)} style={{ fontSize: '24px', width: '64px', height: '64px', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 0 }}>
                        {emoji}
                      </Button>
                    ))}
                  </Row>
                </Stack>
              </Stack>
            )}

            {currentStep === 1 && (
              <Stack gap={24}>
                <Heading level={2}>Personalize Experience</Heading>
                <Select label="Role" placeholder="Select a role" value={formData.role} onChange={(v) => updateField('role', v)} options={roleOptions?.map(r => ({ label: r, value: r })) || []} required />
                <Divider />
                <Stack gap={16}>
                  <Heading level={4}>App Preferences</Heading>
                  <Checkbox label="Email Notifications" description="Get updates via email" checked={formData.emailNotifications} onChange={(v) => updateField('emailNotifications', v)} />
                  <RadioGroup label="Theme Preference" value={formData.theme} onChange={(v) => updateField('theme', v)} direction="horizontal" options={[{ value: 'light', label: 'Light' }, { value: 'dark', label: 'Dark' }]} />
                </Stack>
              </Stack>
            )}

            {currentStep === 2 && (
              <Stack gap={24}>
                <Heading level={2}>Review & Confirm</Heading>
                <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">Check your details before completing the setup.</Text>
                <Stack gap={12} style={{ background: 'var(--ggui-color-surfaceVariant, #f4f4f5)', padding: 'var(--ggui-spacing-4, 16px)', borderRadius: 'var(--ggui-shape-radius-md, 8px)', border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)' }}>
                  <Row justify="between" align="center"><Text weight="semibold">Avatar</Text><Box style={{ fontSize: '28px' }}>{formData.avatar}</Box></Row>
                  <Divider margin={4} />
                  <Row justify="between"><Text weight="semibold">Name</Text><Text>{formData.name}</Text></Row>
                  <Row justify="between"><Text weight="semibold">Email</Text><Text>{formData.email}</Text></Row>
                  <Row justify="between"><Text weight="semibold">Role</Text><Text>{formData.role}</Text></Row>
                  <Row justify="between"><Text weight="semibold">Notifications</Text><Text>{formData.emailNotifications ? 'Enabled' : 'Disabled'}</Text></Row>
                  <Row justify="between"><Text weight="semibold">Theme</Text><Text style={{ textTransform: 'capitalize' }}>{formData.theme}</Text></Row>
                </Stack>
              </Stack>
            )}
          </div>
          <Divider margin={32} />
          <Row justify="between">
            {currentStep > 0 ? <Button variant="ghost" onClick={handleBack} leftIcon={<Icon name="chevron-left" size={16} />}>Go Back</Button> : <div />}
            {currentStep < 2 ? (
              <Button variant="primary" onClick={handleNext} disabled={currentStep === 0 ? !isStep1Valid : !isStep2Valid} rightIcon={<Icon name="chevron-right" size={16} />}>Next Step</Button>
            ) : (
              <Button variant="primary" onClick={() => onComplete(formData)} rightIcon={<Icon name="check" size={16} />}>Complete Setup</Button>
            )}
          </Row>
        </Card>
      </Stack>
    </Container>
  );
}
